function nextImportedCaseId(prefix) {
  const normalizedPrefix = `${prefix || "I"}`.replace(/[^A-Z0-9]/gi, "").toUpperCase() || "I";
  let candidate = "";
  do {
    importedCaseSequence += 1;
    candidate = `${normalizedPrefix}-${Date.now().toString(36).toUpperCase()}-${importedCaseSequence.toString(36).toUpperCase()}`;
  } while (allCases().some((item) => item.id === candidate));
  return candidate;
}

function stableJson(value) {
  if (Array.isArray(value)) return `[${value.map(stableJson).join(",")}]`;
  if (value && typeof value === "object") {
    return `{${Object.keys(value).sort().map((key) => `${JSON.stringify(key)}:${stableJson(value[key])}`).join(",")}}`;
  }
  return JSON.stringify(value);
}

function stableHash(text) {
  let hash = 5381;
  for (let index = 0; index < text.length; index += 1) {
    hash = ((hash << 5) + hash + text.charCodeAt(index)) >>> 0;
  }
  return hash.toString(36).toUpperCase();
}

function caseContentFingerprint(caseItem, sourceType = "custom") {
  const payload = {
    sourceType,
    revealTitle: caseItem.revealTitle || "",
    realPeriod: caseItem.realPeriod || "",
    assets: (caseItem.assets || []).map((assetItem) => ({
      symbol: assetItem.realSymbol || assetItem.symbol || assetItem.maskedSymbol || "",
      type: assetItem.type || "",
      sector: assetItem.sector || "",
      prices: (assetItem.prices || []).map((price) => [
        price.date || "",
        Number(price.open),
        Number(price.high),
        Number(price.low),
        Number(price.close),
        Number(price.volume || 0),
      ]),
    })),
    news: (caseItem.news || []).map((item) => [item.day, item.title || "", item.category || ""]),
    scheduledEvents: (caseItem.scheduledEvents || []).map((item) => [item.day, item.title || "", item.type || "", item.riskLevel || ""]),
  };
  return `${sourceType}-${stableHash(stableJson(payload))}`;
}

function duplicateComparableFingerprint(caseItem) {
  const sourceType = caseItem.assets?.[0]?.source || "custom";
  const scenarioSources = new Set(["imported-package", "starter-builtin"]);
  return caseContentFingerprint(caseItem, scenarioSources.has(sourceType) ? "scenario-package" : sourceType);
}

function findDuplicateCustomCase(importedCase) {
  const sourceType = importedCase.assets?.[0]?.source || "custom";
  const fingerprint = sourceType === "imported-package"
    ? duplicateComparableFingerprint(importedCase)
    : importedCase.sourceFingerprint || caseContentFingerprint(importedCase, sourceType);
  return [...caseLibrary, ...customCaseLibrary].find((item) => {
    const itemFingerprint = duplicateComparableFingerprint(item);
    return itemFingerprint === fingerprint;
  }) || null;
}

function duplicateScenarioPackageError(duplicateCase) {
  const error = new Error(`这个案例包已导入为 ${duplicateCase.id}：${duplicateCase.revealTitle || duplicateCase.maskedTitle}，已跳过重复导入。`);
  error.code = "duplicate-scenario-package";
  error.duplicateCase = duplicateCase;
  return error;
}

function createImportedCase({ title, symbol, rows, assets, qualityReport = null }) {
  const importedAssets = assets || [{
    symbol,
    rows,
    type: "stock",
    sector: "custom",
  }];
  const normalizedSymbols = importedAssets.map((item) => item.symbol.trim().toUpperCase());
  const primarySymbol = normalizedSymbols[0] || symbol.trim().toUpperCase();
  const firstDate = importedAssets.reduce((min, item) => !min || item.rows[0].date < min ? item.rows[0].date : min, "");
  const lastDate = importedAssets.reduce((max, item) => !max || item.rows[item.rows.length - 1].date > max ? item.rows[item.rows.length - 1].date : max, "");
  const id = nextImportedCaseId("U");
  const importedCase = createCase({
    id,
    kind: "custom",
    level: "Custom",
    maskedTitle: title.trim() || `自定义 CSV：${primarySymbol}`,
    maskedBrief: importedAssets.length > 1
      ? `你导入的 ${importedAssets.length} 个本地行情标的。训练中隐藏真实代码和日期，复盘后显示。`
      : "你导入的本地行情案例。训练中仍然隐藏真实日期，复盘后显示 CSV 日期。",
    tags: ["自定义", "CSV", "本地", importedAssets.length > 1 ? "多标的" : "单标的"],
    revealTitle: title.trim() || `自定义 CSV：${normalizedSymbols.join("/")}`,
    realPeriod: `${firstDate} 至 ${lastDate}`,
    importQualityReport: qualityReport,
    dataQuality: importedAssets.length > 1
      ? "本地导入多标的 CSV OHLCV；请确认各标的数据频率、复权、缺失日期和数据源质量。"
      : "本地导入 CSV OHLCV；请自行确认复权、拆股、停牌和数据源质量。",
    assets: importedAssets.map((item, index) => ({
      maskedSymbol: `CUSTOM-${String.fromCharCode(65 + index)}`,
      realSymbol: item.symbol.trim().toUpperCase(),
      maskedName: index === 0 ? "导入主标的" : `导入对比标的 ${index + 1}`,
      type: item.type || (index === 0 ? "stock" : "etf"),
      sector: item.sector || (index === 0 ? "custom" : `custom-${index + 1}`),
      source: "imported-csv",
      prices: item.rows,
    })),
    news: [
      news(0, "这是本地导入案例，系统没有自动新闻。请只根据价格和你自己的研究做训练。", "important"),
    ],
    lessons: [
      "自定义数据的第一责任是确认数据质量。",
      importedAssets.length > 1 ? "多标的案例适合练 ETF 对比、行业轮动和组合风险，不要只盯涨幅最大的那一个。" : "导入案例适合复盘你关心的股票，但不要因为熟悉代码就忽略盲测纪律。",
      "如果数据未复权，拆股和分红可能扭曲收益判断。",
    ],
  });
  importedCase.sourceFingerprint = caseContentFingerprint(importedCase, "imported-csv");
  return importedCase;
}

function createImportedScenarioPackageCase(packageText) {
  const parsed = parseScenarioPackage(packageText);
  const assets = parsed.assets.map((asset, index) => normalizeScenarioPackageAsset(asset, index));
  const qualityReport = buildCsvQualityReport(assets);
  const firstDate = assets.reduce((min, item) => !min || item.rows[0].date < min ? item.rows[0].date : min, "");
  const lastDate = assets.reduce((max, item) => !max || item.rows[item.rows.length - 1].date > max ? item.rows[item.rows.length - 1].date : max, "");
  const id = nextImportedCaseId("P");
  const title = cleanPackageText(parsed.title, "未命名案例包");
  const newsItems = normalizeScenarioPackageNews(parsed.news, assets);
  const sourcePack = normalizeScenarioPackageSourcePack(parsed.sourcePack || parsed.sources, title);
  const scheduledEvents = normalizeScenarioPackageEvents(parsed.scheduledEvents || parsed.events, assets);
  const mission = normalizeScenarioPackageMission(parsed.mission);
  const importedCase = createCase({
    id,
    kind: "custom",
    level: "Custom",
    maskedTitle: cleanPackageText(parsed.maskedTitle, title),
    maskedBrief: cleanPackageText(parsed.maskedBrief, assets.length > 1
      ? `导入案例包包含 ${assets.length} 个标的、${newsItems.length} 条训练新闻和 ${sourcePack.items.length} 条复盘来源。`
      : `导入案例包包含 ${assets[0].symbol} 行情、训练新闻和复盘来源。`),
    tags: normalizePackageStringList(parsed.tags, ["自定义", "案例包", assets.length > 1 ? "多标的" : "单标的"]),
    revealTitle: cleanPackageText(parsed.revealTitle, title),
    realPeriod: cleanPackageText(parsed.realPeriod, `${firstDate} 至 ${lastDate}`),
    importQualityReport: qualityReport,
    dataQuality: cleanPackageText(parsed.dataQuality, "本地导入 JSON 案例包；请确认行情是否复权、新闻摘要是否只保留训练必要信息、来源链接是否可靠。"),
    assets: assets.map((item, index) => ({
      maskedSymbol: cleanPackageText(item.maskedSymbol, `PKG-${String.fromCharCode(65 + index)}`),
      realSymbol: item.symbol,
      maskedName: cleanPackageText(item.maskedName, index === 0 ? "案例包主标的" : `案例包对比标的 ${index + 1}`),
      type: item.type,
      sector: item.sector,
      source: "imported-package",
      prices: item.rows,
    })),
    news: newsItems,
    lessons: normalizePackageStringList(parsed.lessons, [
      "案例包训练重点是把当时新闻、价格反应和自己的纪律分开看。",
      "不要因为复盘来源存在，就在训练前猜真实事件。",
      "导入案例的数据质量由导入者负责，复盘时先核对来源和价格口径。",
    ]),
    learning: normalizeScenarioPackageLearning(parsed.learning || parsed.lessonModule, parsed),
    mission,
    scheduledEvents,
    sourcePack,
  });
  importedCase.sourceFingerprint = caseContentFingerprint(importedCase, "scenario-package");
  return importedCase;
}

