function createBuiltInScenarioPackageCase(casePackage, index) {
  const assets = (casePackage.assets || []).map((packageAsset, assetIndex) => normalizeScenarioPackageAsset(packageAsset, assetIndex));
  const sourcePack = normalizeScenarioPackageSourcePack(casePackage.sourcePack || casePackage.sources, casePackage.title || `Starter C-${index + 1}`);
  const builtInCase = createCase({
    id: `C-${String(index + 1).padStart(3, "0")}`,
    kind: "synthetic",
    level: "Classic",
    maskedTitle: cleanPackageText(casePackage.maskedTitle, `匿名经典案例 ${index + 1}`),
    maskedBrief: cleanPackageText(casePackage.maskedBrief, "经典行情形态训练案例。"),
    tags: normalizePackageStringList(casePackage.tags, ["经典", "训练"]),
    revealTitle: cleanPackageText(casePackage.revealTitle, casePackage.title || `Starter case ${index + 1}`),
    realPeriod: cleanPackageText(casePackage.realPeriod, "匿名历史区间"),
    dataQuality: cleanPackageText(casePackage.dataQuality, "离线合成 OHLCV：用于复现经典行情形态和训练纪律。"),
    assets: assets.map((assetItem, assetIndex) => ({
      maskedSymbol: cleanPackageText(assetItem.maskedSymbol, `CLS-${String.fromCharCode(65 + assetIndex)}`),
      realSymbol: assetItem.symbol,
      maskedName: cleanPackageText(assetItem.maskedName, assetIndex === 0 ? "匿名主标的" : `匿名对比标的 ${assetIndex + 1}`),
      type: assetItem.type,
      sector: assetItem.sector,
      source: "starter-builtin",
      prices: assetItem.rows,
    })),
    news: normalizeScenarioPackageNews(casePackage.news, assets),
    lessons: normalizePackageStringList(casePackage.lessons, [
      "这是内置经典形态训练，用来练原则，不用背真实公司。",
      "先写计划，再看结果；不要用事后答案污染盲测。",
    ]),
    learning: normalizeScenarioPackageLearning(casePackage.learning || casePackage.lessonModule, casePackage),
    mission: normalizeScenarioPackageMission(casePackage.mission),
    scheduledEvents: normalizeScenarioPackageEvents(casePackage.scheduledEvents || casePackage.events, assets),
    corporateActions: Array.isArray(casePackage.corporateActions) ? casePackage.corporateActions : [],
    sourcePack,
  });
  builtInCase.sourceFingerprint = caseContentFingerprint(builtInCase, "scenario-package");
  return builtInCase;
}

