function buildRelativeStrengthPanel(selectedCase = getCase()) {
  const rows = buildRelativeStrengthRows(selectedCase);
  const positiveCount = rows.filter((row) => row.totalReturnPct > 0).length;
  const negativeCount = rows.filter((row) => row.totalReturnPct < 0).length;
  const leading = rows[0];
  const lagging = rows[rows.length - 1];
  const benchmark = rows.find((row) => row.isBenchmark) || rows[0];
  const spread = leading && lagging ? leading.totalReturnPct - lagging.totalReturnPct : 0;
  let regime = {
    level: "good",
    title: "市场结构较均衡",
    detail: `${positiveCount} 个标的上涨，${negativeCount} 个标的下跌。先比较强弱，再决定是否需要交易。`,
  };
  if (negativeCount >= Math.max(2, rows.length - 1) && benchmark?.totalReturnPct < 0) {
    regime = {
      level: "danger",
      title: "风险偏好下降",
      detail: `多数标的走弱，基准 ${benchmark.displaySymbol} 阶段 ${formatPercent(benchmark.totalReturnPct)}。先控制仓位，不要急着证明自己能抄底。`,
    };
  } else if (spread >= 12) {
    regime = {
      level: "warn",
      title: "强弱分化明显",
      detail: `${leading.displaySymbol} 明显强于 ${lagging.displaySymbol}，分化约 ${formatPlainPercent(spread)}。追强前先确认是不是过热。`,
    };
  } else if (positiveCount >= Math.max(2, rows.length - 1)) {
    regime = {
      level: "good",
      title: "广泛走强",
      detail: `多数标的上涨，但仍要比较谁承担了更大回撤和波动。`,
    };
  }
  return { rows, regime };
}

function buildRelativeStrengthRows(selectedCase = getCase()) {
  const finalDay = Math.min(state.day, selectedCase.length - 1);
  const benchmarkAsset = selectedCase.assets.find((item) => item.type === "etf") || selectedCase.assets[0];
  const benchmarkReturn = assetReturnPct(benchmarkAsset, finalDay);
  return selectedCase.assets
    .map((assetItem) => {
      const cappedDay = Math.min(finalDay, assetItem.prices.length - 1);
      const totalReturnPct = assetReturnPct(assetItem, cappedDay);
      const dayChangePct = assetDayChangePct(assetItem, cappedDay);
      const recentVolatilityPct = recentVolatility(assetItem, cappedDay, 5);
      const drawdownPct = maxAssetDrawdown(assetItem, cappedDay);
      return {
        symbol: assetItem.maskedSymbol,
        displaySymbol: displayAssetSymbol(assetItem),
        maskedName: assetItem.maskedName,
        type: assetItem.type,
        isBenchmark: assetItem.maskedSymbol === benchmarkAsset.maskedSymbol,
        totalReturnPct,
        dayChangePct,
        relativeReturnPct: totalReturnPct - benchmarkReturn,
        recentVolatilityPct,
        maxDrawdownPct: drawdownPct,
        lookbackDays: Math.min(5, cappedDay),
        roleLabel: relativeRoleLabel(totalReturnPct - benchmarkReturn, recentVolatilityPct, drawdownPct),
      };
    })
    .sort((a, b) => b.totalReturnPct - a.totalReturnPct);
}

function assetReturnPct(assetItem, finalDay) {
  const first = assetItem.prices[0];
  const final = assetItem.prices[Math.min(finalDay, assetItem.prices.length - 1)];
  return first?.close ? ((final.close - first.close) / first.close) * 100 : 0;
}

function assetDayChangePct(assetItem, day) {
  if (day <= 0) return 0;
  const current = assetItem.prices[Math.min(day, assetItem.prices.length - 1)];
  const previous = assetItem.prices[Math.max(0, Math.min(day - 1, assetItem.prices.length - 1))];
  return previous?.close ? ((current.close - previous.close) / previous.close) * 100 : 0;
}

function assetOpenGapPct(assetItem, day) {
  if (day <= 0) return 0;
  const current = assetItem.prices[Math.min(day, assetItem.prices.length - 1)];
  const previous = assetItem.prices[Math.max(0, Math.min(day - 1, assetItem.prices.length - 1))];
  return previous?.close ? ((current.open - previous.close) / previous.close) * 100 : 0;
}

function gapRiskLevel(assetItem, gapPct) {
  const threshold = assetItem.type === "etf" ? 2 : 5;
  const absGap = Math.abs(gapPct);
  if (absGap >= threshold * 2) return "danger";
  if (absGap >= threshold) return "warn";
  return "good";
}

function recentVolatility(assetItem, finalDay, windowSize = 5) {
  const returns = [];
  const start = Math.max(1, finalDay - windowSize + 1);
  for (let day = start; day <= finalDay; day += 1) {
    returns.push(Math.abs(assetDayChangePct(assetItem, day)));
  }
  if (!returns.length) return 0;
  return returns.reduce((sum, item) => sum + item, 0) / returns.length;
}

function relativeRoleLabel(relativeReturnPct, recentVolatilityPct, maxDrawdownPct) {
  if (relativeReturnPct >= 5 && recentVolatilityPct < 4) return "强势且较稳";
  if (relativeReturnPct >= 5) return "强势高波动";
  if (relativeReturnPct <= -5 && maxDrawdownPct <= -10) return "弱势承压";
  if (relativeReturnPct <= -5) return "跑输基准";
  if (recentVolatilityPct >= 5) return "波动偏高";
  return "接近基准";
}

