  const visibleDate = getVisibleDate(selectedAsset, state.day);
  elements.timelineTitle.textContent = state.revealed ? selectedCase.revealTitle : "行情回放";
  elements.dayLabel.textContent = `第 ${displayDay(state.day)} 天 / ${totalDisplayDays()} 天${visibleDate ? ` · ${visibleDate}` : ""}`;
