function normalizedTrainingContract() {
  const defaults = defaultTrainingContract();
  const current = state.trainingContract || {};
  return {
    ...defaults,
    ...current,
    objective: String(current.objective || defaults.objective),
    riskBudgetPct: clampNumber(Number(current.riskBudgetPct), 1, 30, defaults.riskBudgetPct),
    maxTrades: Math.round(clampNumber(Number(current.maxTrades), 0, 30, defaults.maxTrades)),
    maxPositionPct: clampNumber(Number(current.maxPositionPct), 1, 100, defaults.maxPositionPct),
    minHolds: Math.round(clampNumber(Number(current.minHolds), 0, 20, defaults.minHolds)),
    noAverageDown: current.noAverageDown !== false,
    saved: Boolean(current.saved),
    savedAt: current.savedAt || null,
  };
}

function buildTrainingContractStatus() {
  const contract = normalizedTrainingContract();
  const tradeCount = state.decisions.filter((item) => item.side !== "hold").length;
  const holdCount = state.decisions.filter((item) => item.side === "hold").length;
  const maxDrawdown = getMaxDrawdown();
  const cooldown = getRiskCooldownStatus(contract);
  const maxPositionPct = getMaxConcentrationPct();
  const averageDownEvents = detectAverageDownEvents(chronologicalDecisions()).filter((item) => item.day <= state.day);
  const items = [
    {
      title: "先保存训练合约",
      status: contract.saved ? "pass" : "pending",
      detail: contract.saved ? `目标：${contract.objective || "未写具体目标"}` : "保存后再开始交易，避免事后改规则解释结果。",
    },
    {
      title: "交易次数不超标",
      status: tradeCount <= contract.maxTrades ? "pass" : "fail",
      detail: `当前 ${tradeCount} 次，合约上限 ${contract.maxTrades} 次。`,
    },
    {
      title: "账户回撤不超预算",
      status: maxDrawdown <= contract.riskBudgetPct ? "pass" : "fail",
      detail: `当前最大回撤 ${formatPlainPercent(maxDrawdown)}，合约预算 ${formatPlainPercent(contract.riskBudgetPct)}。`,
    },
    {
      title: "单一仓位不超标",
      status: maxPositionPct <= contract.maxPositionPct ? "pass" : "fail",
      detail: `当前最大仓位 ${formatPlainPercent(maxPositionPct)}，合约上限 ${formatPlainPercent(contract.maxPositionPct)}。`,
    },
    {
      title: "主动观望次数",
      status: holdCount >= contract.minHolds ? "pass" : state.revealed ? "fail" : "pending",
      detail: `当前 ${holdCount} 次，合约要求至少 ${contract.minHolds} 次。`,
    },
    {
      title: "禁止向下补仓",
      status: !contract.noAverageDown || !averageDownEvents.length ? "pass" : "fail",
      detail: contract.noAverageDown
        ? (averageDownEvents.length ? `发现 ${averageDownEvents.length} 次亏损后继续买入。` : "没有发现亏损后继续买入。")
        : "本轮没有启用这条限制。",
    },
  ];
  const score = Math.max(0, Math.round(100
    - items.filter((item) => item.status === "fail").length * 18
    - items.filter((item) => item.status === "pending").length * 6));
  return {
    contract,
    score,
    passed: contract.saved && items.every((item) => item.status !== "fail") && (state.revealed ? items.every((item) => item.status === "pass") : true),
    stats: { tradeCount, holdCount, maxDrawdown, maxPositionPct, averageDownCount: averageDownEvents.length, riskCoolingActive: cooldown.active, riskCoolingBreachDay: cooldown.breachDay },
    items,
  };
}

function getRiskCooldownStatus(contract = normalizedTrainingContract()) {
  if (!contract.saved) {
    return { active: false, contract, breachDay: null, drawdownPct: 0 };
  }
  const breach = findDrawdownBreach(contract.riskBudgetPct);
  return {
    active: Boolean(breach),
    contract,
    breachDay: breach?.day ?? null,
    drawdownPct: breach?.drawdownPct ?? 0,
  };
}

function findDrawdownBreach(limitPct) {
  if (!Number.isFinite(limitPct) || limitPct <= 0) return null;
  let peak = 0;
  const points = [...(state.equityCurve || [])].sort((a, b) => a.day - b.day);
  for (const point of points) {
    const equity = Number(point.equity) || 0;
    peak = Math.max(peak, equity);
    const drawdownPct = peak ? ((peak - equity) / peak) * 100 : 0;
    if (drawdownPct > limitPct) {
      return { day: point.day, drawdownPct };
    }
  }
  return null;
}

function detectAverageDownEvents(decisions = chronologicalDecisions()) {
  const openLots = {};
  const events = [];
  decisions.forEach((decision) => {
    if (decision.side === "sell") {
      let remainingSell = decision.quantity;
      const lots = openLots[decision.symbol] || [];
      lots.forEach((lot) => {
        if (remainingSell <= 0) return;
        const closeQuantity = Math.min(lot.quantity, remainingSell);
        lot.quantity -= closeQuantity;
        remainingSell -= closeQuantity;
      });
      openLots[decision.symbol] = lots.filter((lot) => lot.quantity > 0);
      return;
    }
    if (decision.side !== "buy") return;
    const lots = openLots[decision.symbol] || [];
    const openQuantity = lots.reduce((sum, lot) => sum + lot.quantity, 0);
    const openCost = lots.reduce((sum, lot) => sum + lot.quantity * lot.price, 0);
    const averageCost = openQuantity ? openCost / openQuantity : decision.price;
    if (openQuantity > 0 && decision.price < averageCost * 0.985) {
      events.push({
        symbol: decision.symbol,
        day: decision.day,
        price: decision.price,
        averageCost,
        detail: `第 ${displayDay(decision.day)} 天 ${decision.symbol} 在低于持仓成本时继续买入。`,
      });
    }
    lots.push({ quantity: decision.quantity, price: decision.price, day: decision.day });
    openLots[decision.symbol] = lots;
  });
  return events;
}

