function calculateAllocationExposure(positions = state.positions, cash = state.cash) {
  const positionValue = getPositionValue(positions);
  const equity = roundPrice(cash + positionValue) || riskPolicy.initialCash;
  const exposure = {
    equity,
    cashPct: equity ? (cash / equity) * 100 : 0,
    etfPct: 0,
    stockPct: 0,
    sectorPct: 0,
    satellitePct: 0,
    maxSingleStockPct: 0,
    maxSectorPct: 0,
  };
  const sectorWeights = {};
  Object.entries(positions).forEach(([symbol, position]) => {
    if (!position?.quantity) return;
    const assetItem = getAsset(symbol);
    const value = position.quantity * getPrice(symbol);
    const weightPct = equity ? (value / equity) * 100 : 0;
    if (assetItem.type === "etf") exposure.etfPct += weightPct;
    if (assetItem.type === "stock") {
      exposure.stockPct += weightPct;
      exposure.maxSingleStockPct = Math.max(exposure.maxSingleStockPct, weightPct);
    }
    if (assetItem.type === "sector") exposure.sectorPct += weightPct;
    if (assetItem.type !== "etf") exposure.satellitePct += weightPct;
    sectorWeights[assetItem.sector] = (sectorWeights[assetItem.sector] || 0) + weightPct;
  });
  exposure.maxSectorPct = Math.max(0, ...Object.values(sectorWeights));
  return exposure;
}

function buildAllocationStatus(positions = state.positions, cash = state.cash) {
  const blueprint = normalizedAllocationBlueprint();
  const exposure = calculateAllocationExposure(positions, cash);
  const items = [
    {
      title: "先保存配置蓝图",
      status: blueprint.saved ? "pass" : "pending",
      detail: blueprint.saved ? `目标：${blueprint.objective || "未写具体目标"}` : "保存 ETF 核心仓、卫星仓和现金底线，避免临时重仓单股。",
    },
    {
      title: "ETF 核心仓比例",
      status: exposure.etfPct >= blueprint.minEtfPct || exposure.satellitePct === 0 ? "pass" : "warn",
      detail: `当前 ETF ${formatPlainPercent(exposure.etfPct)}，蓝图要求至少 ${formatPlainPercent(blueprint.minEtfPct)}。`,
    },
    {
      title: "单股/行业卫星仓",
      status: exposure.satellitePct <= blueprint.maxSatellitePct ? "pass" : "fail",
      detail: `当前卫星仓 ${formatPlainPercent(exposure.satellitePct)}，蓝图上限 ${formatPlainPercent(blueprint.maxSatellitePct)}。`,
    },
    {
      title: "单只股票上限",
      status: exposure.maxSingleStockPct <= blueprint.maxSingleStockPct ? "pass" : "fail",
      detail: `当前最大单股 ${formatPlainPercent(exposure.maxSingleStockPct)}，蓝图上限 ${formatPlainPercent(blueprint.maxSingleStockPct)}。`,
    },
    {
      title: "行业集中度",
      status: exposure.maxSectorPct <= blueprint.maxSectorPct ? "pass" : "fail",
      detail: `当前最大行业 ${formatPlainPercent(exposure.maxSectorPct)}，蓝图上限 ${formatPlainPercent(blueprint.maxSectorPct)}。`,
    },
    {
      title: "现金底线",
      status: exposure.cashPct >= blueprint.minCashPct ? "pass" : "fail",
      detail: `当前现金 ${formatPlainPercent(exposure.cashPct)}，蓝图要求至少 ${formatPlainPercent(blueprint.minCashPct)}。`,
    },
  ];
  const failCount = items.filter((item) => item.status === "fail").length;
  const warnCount = items.filter((item) => item.status === "warn").length;
  const pendingCount = items.filter((item) => item.status === "pending").length;
  const score = Math.max(0, Math.round(100 - failCount * 20 - warnCount * 9 - pendingCount * 6));
  return {
    blueprint,
    exposure,
    items,
    score,
    passed: blueprint.saved && failCount === 0,
    level: failCount ? "danger" : warnCount || pendingCount ? "warn" : "good",
  };
}

