function upsertRulebookRuleFromReflection(reflection, run = null) {
  const text = (reflection?.nextRule || "").trim();
  if (text.length < 8) return null;
  profile.rulebook = profile.rulebook || [];
  const normalizedText = normalizeRuleText(text);
  const existing = profile.rulebook.find((item) => normalizeRuleText(item.text) === normalizedText);
  const tags = classifyRuleTags(text);
  if (existing) {
    existing.timesSeen = (existing.timesSeen || 1) + 1;
    existing.lastSeenAt = reflection.savedAt || new Date().toISOString();
    existing.active = existing.active !== false;
    existing.tags = [...new Set([...(existing.tags || []), ...tags])];
    existing.sourceCaseId = run?.caseId || existing.sourceCaseId || state.caseId;
    existing.sourceRunId = run?.id || existing.sourceRunId || state.completedRunId;
    return existing;
  }
  const rule = {
    id: `rule-${Date.now().toString(36)}-${profile.rulebook.length + 1}`,
    text,
    tags,
    active: true,
    timesSeen: 1,
    sourceCaseId: run?.caseId || state.caseId,
    sourceRunId: run?.id || state.completedRunId,
    createdAt: reflection.savedAt || new Date().toISOString(),
    lastSeenAt: reflection.savedAt || new Date().toISOString(),
  };
  profile.rulebook.unshift(rule);
  profile.rulebook = profile.rulebook.slice(0, 30);
  return rule;
}

function normalizeRuleText(text) {
  return String(text || "").toLowerCase().replace(/\s+/g, " ").trim();
}

function classifyRuleTags(text) {
  const rule = String(text || "").toLowerCase();
  const tags = [];
  if (/观望|hold|wait|不交易|先等/.test(rule)) tags.push("hold-first");
  if (/追涨|fomo|大涨|突破|冲动/.test(rule)) tags.push("no-fomo");
  if (/补仓|摊低|越跌越买|average/.test(rule)) tags.push("no-average-down");
  if (/止损|亏损线|失效|跌破/.test(rule)) tags.push("stop-loss");
  if (/仓位|单仓|不超过|最多|%|％/.test(rule)) tags.push("position-limit");
  if (/确认|confirm|站上|重新评估|条件/.test(rule)) tags.push("wait-confirmation");
  return tags.length ? tags : ["general"];
}

function extractFirstPercent(text) {
  const match = String(text || "").match(/(\d+(?:\.\d+)?)\s*(?:%|％)/);
  return match ? Number.parseFloat(match[1]) : Number.NaN;
}

function buildRulebookCoachItem({ side, symbol, preview, emotion }) {
  const activeRules = (profile.rulebook || []).filter((item) => item.active !== false).slice(0, 5);
  if (!activeRules.length) {
    return { level: "good", title: "个人规则库", detail: "还没有个人硬规则。完成复盘反思后，下一轮硬规则会自动沉淀到这里。" };
  }
  const issues = [];
  activeRules.forEach((rule) => {
    const tags = rule.tags || classifyRuleTags(rule.text);
    const percentLimit = extractFirstPercent(rule.text);
    if (tags.includes("hold-first") && !state.decisions.some((item) => item.side === "hold") && side !== "hold") {
      issues.push({ level: "warn", text: `规则“${rule.text}”要求先观望，但本轮还没有主动观望。` });
    }
    if (tags.includes("no-fomo") && side === "buy" && ["fomo", "greed"].includes(emotion)) {
      issues.push({ level: "danger", text: `规则“${rule.text}”和当前情绪冲突。` });
    }
    if (tags.includes("no-average-down") && side === "buy") {
      const position = state.positions[symbol];
      if (position?.quantity > 0 && getPrice(symbol) < position.averageCost * 0.985) {
        issues.push({ level: "danger", text: `规则“${rule.text}”禁止亏损后继续补仓。` });
      }
    }
    if (tags.includes("position-limit") && Number.isFinite(percentLimit) && side !== "hold" && preview?.symbolWeightPct > percentLimit) {
      issues.push({ level: "danger", text: `规则“${rule.text}”限制仓位，本次后约 ${formatPlainPercent(preview.symbolWeightPct)}。` });
    }
    if (tags.includes("wait-confirmation") && side === "buy" && state.day <= 1) {
      issues.push({ level: "warn", text: `规则“${rule.text}”要求确认，当前还在案例早期。` });
    }
  });
  const danger = issues.find((item) => item.level === "danger");
  if (danger) return { level: "danger", title: "违反个人硬规则", detail: danger.text };
  if (issues.length) return { level: "warn", title: "个人规则提醒", detail: issues[0].text };
  return { level: "good", title: "个人规则库", detail: `已检查 ${activeRules.length} 条个人硬规则，当前动作没有明显冲突。` };
}

function toggleRulebookRule(ruleId) {
  const rule = (profile.rulebook || []).find((item) => item.id === ruleId);
  if (!rule) return;
  rule.active = rule.active === false;
  saveProfile();
  renderProfile();
}

