function renderCoursePath() {
  const recommendedCase = findNextRecommendedCase();
  const totalCases = coursePath.reduce((sum, item) => sum + item.cases.length, 0);
  const doneCases = coursePath.reduce((sum, item) => sum + countQualifiedCases(item.cases), 0);
  const hideMeta = currentModePolicy().hideCaseMeta && !state.revealed;
  elements.courseProgressLabel.textContent = `${doneCases} / ${totalCases}`;
  elements.coursePath.innerHTML = coursePath
    .map((level, levelIndex) => {
      const done = countQualifiedCases(level.cases);
      const isDone = done === level.cases.length;
      const isCurrent = !isDone && level.cases.includes(state.caseId);
      const caseLabels = level.cases
        .map((caseId) => {
          const caseItem = allCases().find((item) => item.id === caseId);
          const status = getCasePathStatus(caseItem);
          const marker = status.qualified ? "合格" : recommendedCase?.id === caseId ? "推荐" : status.unlocked ? "可练" : "锁定";
          const tagClass = status.qualified ? "real" : recommendedCase?.id === caseId ? "important" : status.unlocked ? "" : "locked";
          return `<span class="tag ${tagClass}" title="${escapeHtml(status.reason)}">${displayCaseId(caseItem)} · ${marker}</span>`;
        })
        .join("");
      return `
        <article class="course-item ${isDone ? "is-done" : ""} ${isCurrent ? "is-current" : ""}">
          <strong>${hideMeta ? `匿名阶段 ${levelIndex + 1}` : level.title}</strong>
          <p>${hideMeta ? "考试模式隐藏阶段主题。按解锁顺序推进即可，不要根据阶段名称猜真实场景。" : level.goal}</p>
          <div class="course-meta">${caseLabels}</div>
          <p>${done} / ${level.cases.length} 合格。${isDone ? "本阶段已完成。" : "先按推荐顺序推进，不要急着跳到高难度。"}</p>
        </article>
      `;
    })
    .join("");
}

function renderProfile() {
  const runs = profile.completedRuns;
  const hideMeta = currentModePolicy().hideCaseMeta && !state.revealed;
  if (!runs.length) {
    const starterQueue = buildTrainingQueue({ runs: [], topMistakes: [], topEmotions: [] });
    const starterPlan = buildDailyTrainingPlan({ runs: [], trainingQueue: starterQueue });
    elements.profileSummaryLabel.textContent = "暂无记录";
    elements.profilePanel.innerHTML = `
      <article class="profile-item">
        <strong>还没有长期画像</strong>
        <p>完成至少 1 个案例后，系统会统计你的常见错误、情绪倾向和纪律得分。</p>
      </article>
      ${renderDailyTrainingPlan(starterPlan)}
    `;
    return;
  }

  const averageScore = runs.reduce((sum, item) => sum + item.disciplineScore, 0) / runs.length;
  const averageReturn = runs.reduce((sum, item) => sum + item.returnPct, 0) / runs.length;
  const missionRuns = runs.filter((item) => Number.isFinite(item.missionScore));
  const missionPassRate = missionRuns.length
    ? (missionRuns.filter((item) => item.missionPassed).length / missionRuns.length) * 100
    : 0;
  const coachRuns = runs.filter((item) => Number.isFinite(item.averageCoachScore));
  const averageCoachScore = coachRuns.length
    ? coachRuns.reduce((sum, item) => sum + item.averageCoachScore, 0) / coachRuns.length
    : Number.NaN;
  const lessonRuns = runs.filter((item) => Number.isFinite(item.lessonAttempts));
  const lessonPassRate = lessonRuns.length
    ? (lessonRuns.filter((item) => item.lessonPassed).length / lessonRuns.length) * 100
    : 0;
  const lessonFirstTryRate = lessonRuns.length
    ? (lessonRuns.filter((item) => item.lessonFirstTry).length / lessonRuns.length) * 100
    : 0;
  const averageLessonAttempts = lessonRuns.length
    ? lessonRuns.reduce((sum, item) => sum + item.lessonAttempts, 0) / lessonRuns.length
    : Number.NaN;
  const topMistakes = topEntries(profile.mistakeCounts, 4);
  const topEmotions = topEntries(profile.emotionCounts, 4);
  const topRootCauses = topEntries(runs.reduce((record, item) => {
    if (item.rootCausePrimary) record[item.rootCausePrimary] = (record[item.rootCausePrimary] || 0) + 1;
    return record;
  }, {}), 4);
  const mistakeNotebook = buildMistakeNotebookReport(runs, profile.mistakeCounts);
  const latestRemediation = [...runs].reverse().find((item) => item.remediation)?.remediation;
  const reflectedRuns = runs.filter((item) => item.reflection && item.reflection.nextRule);
  const latestReflection = reflectedRuns[reflectedRuns.length - 1]?.reflection;
  const activeRules = (profile.rulebook || []).filter((item) => item.active !== false);
  const sampleQuality = buildSampleQualityReport(runs);
  const examReport = buildValidBlindExamReport(runs);
  const coverageReport = buildScenarioCoverageReport(runs);
  const skillRadar = buildSkillRadarMetrics({ runs, averageScore, missionPassRate, averageCoachScore, lessonPassRate, lessonFirstTryRate, reflectionRate: (reflectedRuns.length / runs.length) * 100 });
  const liveReadiness = buildLiveReadinessReport({ runs, sampleQuality, examReport, coverageReport, skillRadar, activeRuleCount: activeRules.length });
  const trainingQueue = buildTrainingQueue({ runs, topMistakes, topEmotions, averageScore, missionPassRate, averageCoachScore, lessonPassRate, lessonFirstTryRate, sampleQuality, examReport, coverageReport, liveReadiness });
  const ledgerReport = buildTrainingLedgerReport(runs);
  const planAdherence = buildPlanAdherenceReport(runs);
  const reviewSchedule = buildReviewScheduleReport(runs);
  const trend = buildTrainingTrend(runs);
  const dailyPlan = buildDailyTrainingPlan({ runs, trainingQueue, skillRadar, trend });
  elements.profileSummaryLabel.textContent = `${runs.length} 次 · 平均 ${Math.round(averageScore)}`;
  elements.profilePanel.innerHTML = `
    <article class="profile-item">
      <strong>总体状态</strong>
      <div class="profile-meta">
        <span class="tag">完成 ${runs.length} 次</span>
        <span class="tag">平均纪律 ${Math.round(averageScore)}/100</span>
        <span class="tag">平均下单 ${Number.isFinite(averageCoachScore) ? `${Math.round(averageCoachScore)}/100` : "暂无"}</span>
        <span class="tag">平均收益 ${formatPercent(averageReturn)}</span>
        <span class="tag">任务通过 ${formatPlainPercent(missionPassRate)}</span>
        <span class="tag">课程通过 ${lessonRuns.length ? formatPlainPercent(lessonPassRate) : "暂无"}</span>
      </div>
    </article>
    <article class="profile-item">
      <strong>常见错误</strong>
      <p>${topMistakes.length ? topMistakes.map(([name, count]) => `${name} ×${count}`).join("；") : "暂未识别出高频错误。"}</p>
    </article>
    <article class="profile-item">
      <strong>情绪倾向</strong>
      <p>${topEmotions.length ? topEmotions.map(([name, count]) => `${emotionLabel(name)} ×${count}`).join("；") : "还没有足够情绪记录。"}</p>
    </article>
    <article class="profile-item">
      <strong>高频根因</strong>
      <p>${topRootCauses.length ? topRootCauses.map(([name, count]) => `${name} ×${count}`).join("；") : "新记录会开始统计首要根因，旧记录可能没有这项数据。"}</p>
    </article>
    ${renderMistakeNotebook(mistakeNotebook, hideMeta)}
    <article class="profile-item">
      <strong>最近训练</strong>
      <p>${runs.slice(-3).reverse().map((item) => `${hideMeta ? displayCaseId(getCase(item.caseId)) : item.caseId}：纪律 ${item.disciplineScore}/100，任务 ${Number.isFinite(item.missionScore) ? `${item.missionScore}/100` : "旧记录"}，下单 ${Number.isFinite(item.averageCoachScore) ? `${Math.round(item.averageCoachScore)}/100` : "旧记录"}，收益 ${formatPercent(item.returnPct)}`).join("；")}</p>
    </article>
    ${renderTrainingLedger(ledgerReport, hideMeta)}
    ${renderPlanAdherence(planAdherence, hideMeta)}
    ${renderReviewSchedule(reviewSchedule, hideMeta)}
    ${renderSampleQualityCard(sampleQuality, runs.length)}
    ${renderExamPerformanceCard(examReport)}
    ${renderScenarioCoverageCard(coverageReport)}
    ${renderLiveReadinessCard(liveReadiness)}
    ${renderTrainingTrendCard(trend)}
    ${renderDailyTrainingPlan(dailyPlan)}
    <article class="profile-item">
      <strong>课程理解</strong>
      <p>${lessonRuns.length ? `通过率 ${formatPlainPercent(lessonPassRate)}，一次答对 ${formatPlainPercent(lessonFirstTryRate)}，平均 ${averageLessonAttempts.toFixed(1)} 次通过检查题。` : "旧记录没有课程检查数据。后续完成案例后会开始统计。"}</p>
    </article>
    ${renderSkillRadarCard(skillRadar)}
    ${renderReflectionCard(latestReflection, reflectedRuns.length, runs.length)}
    ${renderRulebookCard(profile.rulebook || [])}
    ${renderTrainingQueueCard(trainingQueue, hideMeta)}
    ${renderRemediationCard(latestRemediation, hideMeta)}
    ${renderProfileRecommendationCard(buildProfileRecommendation({ topMistakes, topEmotions, averageScore, missionPassRate, sampleQuality, examReport, coverageReport, liveReadiness }), hideMeta)}
  `;
}

function buildDailyTrainingPlan({ runs = profile.completedRuns, trainingQueue = buildTrainingQueue({ runs }), skillRadar = null, trend = null } = {}) {
  const queue = trainingQueue.length ? trainingQueue : [trainingQueueItemFromPath()];
  const primary = queue[0];
  const radar = skillRadar || buildSkillRadarMetrics({ runs });
  const weakestSkill = [...radar].sort((a, b) => a.score - b.score)[0] || { label: "基础纪律", score: 0, detail: "先完成第一轮盲测训练。" };
  const currentTrend = trend || buildTrainingTrend(runs);
  const highPriorityCount = queue.filter((item) => item.priority === "high").length;
  const estimatedMinutes = primary.priority === "high" ? 45 : primary.priority === "low" ? 25 : 35;
  const modeSuggestion = primary.launchMode === "random-blind"
    ? "exam"
    : primary.priority === "high" || weakestSkill.score < 65 ? "novice" : currentTrend.level === "good" ? "advanced" : "novice";
  const plan = {
    title: primary.priority === "high" ? "今日先补最危险弱项" : "今日按路径稳定推进",
    summary: `${primary.caseId} · ${primary.caseTitle}。主攻 ${primary.focus}，预计 ${estimatedMinutes} 分钟。`,
    primary,
    queue,
    weakestSkill,
    trend: currentTrend,
    estimatedMinutes,
    modeSuggestion,
    highPriorityCount,
    steps: [
      {
        title: "1. 训练前热身",
        detail: `先读本关课程和任务卡，保存训练合约；本轮只允许围绕“${primary.focus}”做决策。`,
        check: "检查题通过、合约保存、最大仓位和回撤预算写清楚。",
      },
      {
        title: "2. 主训练",
        detail: primary.constraint,
        check: `使用${trainingModeLabel(modeSuggestion)}，遇到关键节点先写判断，不直接跳复盘。`,
      },
      {
        title: "3. 复盘动作",
        detail: "结束后先看揭晓纪律、任务评分、下单质量、文字质量，再看收益。",
        check: "逐笔审计至少看 2 条，写下做对的事、最大错误和下一轮硬规则。",
      },
      {
        title: "4. 验收标准",
        detail: primary.passCriteria.join("；"),
        check: currentTrend.level === "danger" ? "如果最近趋势退步，本轮未达标就不要升难度。" : "达标后再执行队列里的下一项训练。",
      },
    ],
    stopRules: [
      "没有保存训练合约，不开始交易。",
      "出现红色教练提醒，不加仓，只能观望、减仓或重写计划。",
      "想提前揭晓时，先看结束前纪律检查；低于 70/100 不把本轮当合格训练。",
    ],
  };
  return plan;
}

