function createActiveTrainingPlanSnapshot(caseId, focus = "") {
  const queue = buildTrainingQueue();
  const plan = buildDailyTrainingPlan({ trainingQueue: queue });
  const selected = queue.find((item) => item.caseId === caseId && (!focus || item.focus === focus))
    || queue.find((item) => item.caseId === caseId)
    || plan.primary;
  const sourcePlan = selected === plan.primary
    ? plan
    : buildDailyTrainingPlan({ trainingQueue: [selected, ...queue.filter((item) => item !== selected)] });
  return {
    title: selected.title,
    caseId: selected.caseId,
    caseTitle: selected.caseTitle,
    focus: selected.focus,
    priority: selected.priority,
    reason: selected.reason,
    constraint: selected.constraint,
    passCriteria: selected.passCriteria,
    estimatedMinutes: sourcePlan.estimatedMinutes,
    modeSuggestion: sourcePlan.modeSuggestion,
    launchMode: selected.launchMode || "case",
    stopRules: sourcePlan.stopRules,
    startedAt: new Date().toISOString(),
  };
}

