function drawChart(assetItem) {
  const canvas = elements.priceChart;
  const ctx = canvas.getContext("2d");
  const dpr = window.devicePixelRatio || 1;
  const rect = canvas.getBoundingClientRect();
  canvas.width = Math.max(1, Math.floor(rect.width * dpr));
  canvas.height = Math.max(1, Math.floor(rect.height * dpr));
  ctx.scale(dpr, dpr);

  const width = rect.width;
  const height = rect.height;
  const points = assetItem.prices.slice(0, state.day + 1);
  const showVolume = state.showVolume !== false;
  const showMovingAverage = state.showMovingAverage !== false;
  const mode = state.chartMode || "line";
  const padding = { top: 28, right: 58, bottom: 34, left: 58 };
  const volumeHeight = showVolume ? Math.min(92, Math.max(58, height * 0.22)) : 0;
  const volumeGap = showVolume ? 16 : 0;
  const min = Math.min(...points.map((item) => item.low));
  const max = Math.max(...points.map((item) => item.high));
  const range = Math.max(1, max - min);
  const plotWidth = width - padding.left - padding.right;
  const priceHeight = height - padding.top - padding.bottom - volumeHeight - volumeGap;
  const priceBottom = padding.top + priceHeight;
  const maxVolume = Math.max(1, ...points.map((item) => item.volume || 0));

  ctx.clearRect(0, 0, width, height);
  ctx.strokeStyle = "#d5dee4";
  ctx.lineWidth = 1;
  for (let i = 0; i < 4; i += 1) {
    const y = padding.top + (priceHeight / 3) * i;
    ctx.beginPath();
    ctx.moveTo(padding.left, y);
    ctx.lineTo(width - padding.right, y);
    ctx.stroke();
  }

  const xFor = (index) => padding.left + (index / Math.max(1, points.length - 1)) * plotWidth;
  const yFor = (price) => padding.top + (1 - (price - min) / range) * priceHeight;

  if (mode === "candles") {
    drawCandles(ctx, points, xFor, yFor, plotWidth);
  } else {
    drawPriceLine(ctx, points.map((point, index) => ({ index, value: point.close })), xFor, yFor, "#0f766e", 2.6);
  }

  if (showMovingAverage) {
    drawMovingAverage(ctx, points, 5, xFor, yFor, "#8a5cf6");
    drawMovingAverage(ctx, points, 20, xFor, yFor, "#a15c07");
  }

  drawDecisionMarkers(ctx, assetItem, points, xFor, yFor, padding.top, priceBottom);

  if (showVolume) {
    const volumeTop = priceBottom + volumeGap;
    ctx.strokeStyle = "#d5dee4";
    ctx.beginPath();
    ctx.moveTo(padding.left, volumeTop);
    ctx.lineTo(width - padding.right, volumeTop);
    ctx.stroke();
    points.forEach((point, index) => {
      const x = xFor(index);
      const previous = points[Math.max(0, index - 1)]?.close || point.open;
      const up = point.close >= previous;
      const barHeight = ((point.volume || 0) / maxVolume) * (volumeHeight - 12);
      const barWidth = Math.max(2, Math.min(10, plotWidth / Math.max(8, points.length) * 0.62));
      ctx.fillStyle = up ? "rgba(19, 115, 51, 0.34)" : "rgba(180, 35, 24, 0.32)";
      ctx.fillRect(x - barWidth / 2, height - padding.bottom - barHeight, barWidth, barHeight);
    });
    ctx.fillStyle = "#6c7a86";
    ctx.font = "12px Segoe UI, Arial";
    ctx.textAlign = "left";
    ctx.fillText("Volume", padding.left, volumeTop + 13);
  }

  const last = points[points.length - 1];
  const lastX = xFor(points.length - 1);
  const lastY = yFor(last.close);
  ctx.fillStyle = "#0f766e";
  ctx.beginPath();
  ctx.arc(lastX, lastY, 4, 0, Math.PI * 2);
  ctx.fill();

  ctx.fillStyle = "#6c7a86";
  ctx.font = "12px Segoe UI, Arial";
  ctx.textAlign = "right";
  ctx.fillText(formatCurrency(max), width - 10, padding.top + 4);
  ctx.fillText(formatCurrency(min), width - 10, priceBottom);
  const startLabel = state.revealed && assetItem.prices[0]?.date ? assetItem.prices[0].date : "第 1 天";
  const endLabel = state.revealed && assetItem.prices[state.day]?.date ? assetItem.prices[state.day].date : `第 ${displayDay(state.day)} 天`;
  ctx.textAlign = "left";
  ctx.fillText(startLabel, padding.left, height - 12);
  ctx.textAlign = "right";
  ctx.fillText(endLabel, width - padding.right, height - 12);
  if (showMovingAverage) {
    ctx.textAlign = "left";
    ctx.fillStyle = "#8a5cf6";
    ctx.fillText("MA5", padding.left + 86, 16);
    ctx.fillStyle = "#a15c07";
    ctx.fillText("MA20", padding.left + 126, 16);
  }
}

function buildDecisionMarkers(assetItem, points) {
  return chronologicalDecisions()
    .filter((item) => item.day <= state.day && item.day < points.length)
    .filter((item) => item.symbol === assetItem.maskedSymbol || (item.side === "hold" && item.symbol === assetItem.maskedSymbol))
    .map((item) => {
      const point = points[item.day] || points[points.length - 1];
      const price = item.side === "hold" ? point.close : item.price || point.close;
      const label = item.side === "buy" ? "B" : item.side === "sell" ? "S" : "H";
      const color = item.side === "buy" ? "#137333" : item.side === "sell" ? "#b42318" : "#6c7a86";
      return {
        day: item.day,
        side: item.side,
        symbol: item.symbol,
        price,
        label,
        color,
        quantity: item.quantity || 0,
        coachLevel: item.coach?.level || "",
        coachScore: item.coach?.score,
      };
    });
}

function drawDecisionMarkers(ctx, assetItem, points, xFor, yFor, top, bottom) {
  const markers = buildDecisionMarkers(assetItem, points);
  if (!markers.length) return;

  markers.forEach((marker, index) => {
    const x = xFor(marker.day);
    const baseY = marker.side === "hold"
      ? top + 18 + (index % 2) * 16
      : Math.min(bottom - 12, Math.max(top + 18, yFor(marker.price)));
    ctx.fillStyle = marker.color;
    ctx.strokeStyle = "#fff";
    ctx.lineWidth = 2;
    ctx.beginPath();
    if (marker.side === "buy") {
      ctx.moveTo(x, baseY - 10);
      ctx.lineTo(x - 7, baseY + 6);
      ctx.lineTo(x + 7, baseY + 6);
      ctx.lineTo(x, baseY - 10);
    } else if (marker.side === "sell") {
      ctx.moveTo(x, baseY + 10);
      ctx.lineTo(x - 7, baseY - 6);
      ctx.lineTo(x + 7, baseY - 6);
      ctx.lineTo(x, baseY + 10);
    } else {
      ctx.arc(x, baseY, 7, 0, Math.PI * 2);
    }
    ctx.fill();
    ctx.stroke();

    const badgeY = marker.side === "buy" ? baseY + 20 : marker.side === "sell" ? baseY - 14 : baseY + 4;
    ctx.fillStyle = marker.color;
    ctx.font = "700 11px Segoe UI, Arial";
    ctx.textAlign = "center";
    ctx.fillText(marker.label, x, badgeY);
    if (marker.coachLevel === "danger") {
      ctx.fillStyle = "#b42318";
      ctx.beginPath();
      ctx.arc(x + 9, baseY - 9, 3, 0, Math.PI * 2);
      ctx.fill();
    }
  });

  ctx.fillStyle = "#6c7a86";
  ctx.font = "12px Segoe UI, Arial";
  ctx.textAlign = "left";
  ctx.fillText("B 买入 · S 卖出 · H 观望", 58, 16);
}

function drawCandles(ctx, points, xFor, yFor, plotWidth) {
  const candleWidth = Math.max(3, Math.min(12, plotWidth / Math.max(8, points.length) * 0.7));
  points.forEach((point, index) => {
    const x = xFor(index);
    const up = point.close >= point.open;
    const color = up ? "#137333" : "#b42318";
    const openY = yFor(point.open);
    const closeY = yFor(point.close);
    const highY = yFor(point.high);
    const lowY = yFor(point.low);
    ctx.strokeStyle = color;
    ctx.fillStyle = color;
    ctx.lineWidth = 1.3;
    ctx.beginPath();
    ctx.moveTo(x, highY);
    ctx.lineTo(x, lowY);
    ctx.stroke();
    const bodyTop = Math.min(openY, closeY);
    const bodyHeight = Math.max(2, Math.abs(closeY - openY));
    ctx.fillRect(x - candleWidth / 2, bodyTop, candleWidth, bodyHeight);
  });
}

function drawPriceLine(ctx, points, xFor, yFor, color, width) {
  if (!points.length) return;
  ctx.strokeStyle = color;
  ctx.lineWidth = width;
  ctx.beginPath();
  points.forEach((point, index) => {
    const x = xFor(point.index);
    const y = yFor(point.value);
    if (index === 0) ctx.moveTo(x, y);
    else ctx.lineTo(x, y);
  });
  ctx.stroke();
}

function drawMovingAverage(ctx, points, windowSize, xFor, yFor, color) {
  const series = points
    .map((_, index) => ({ index, value: movingAverage(points, index, windowSize) }))
    .filter((point) => Number.isFinite(point.value));
  drawPriceLine(ctx, series, xFor, yFor, color, 1.7);
}

