function buildRiskDashboard(selectedCase) {
  const totals = getPortfolioTotals();
  const funding = buildFundingSummary(totals);
  const settlement = buildSettlementSummary();
  const policy = currentModePolicy();
  const equity = totals.equity || riskPolicy.initialCash;
  const cashPct = equity ? (state.cash / equity) * 100 : 0;
  const positionRows = buildPositionExposureRows(equity, policy);
  const sectorRows = buildSectorExposureRows(equity);
  const stressRows = buildStressRows(equity);
  const gapRows = buildGapRiskRows(selectedCase, state.day);
  const eventRiskRows = buildEventRiskRows(selectedCase, state.day);
  const planRows = buildOpenPositionPlanRows();
  const allocationStatus = buildAllocationStatus();
  const contractStatus = buildTrainingContractStatus();
  const alerts = buildRiskAlerts({ cashPct, positionRows, sectorRows, gapRows, eventRiskRows, settlement, planRows, allocationStatus, contractStatus, policy });
  return {
    modeLabel: policy.label,
    equity,
    cashPct,
    reserveCashPct: policy.reserveCashRatio * 100,
    maxDrawdownPct: getMaxDrawdown(),
    maxPositionPct: positionRows.reduce((max, item) => Math.max(max, item.weightPct), 0),
    turnoverPct: getTurnoverPct(),
    funding,
    settlement,
    positionRows,
    sectorRows,
    stressRows,
    gapRows,
    eventRiskRows,
    planRows,
    allocationStatus,
    contractStatus,
    alerts,
    equitySeries: buildEquitySeries(),
    benchmarkSeries: buildBenchmarkEquitySeries(selectedCase),
  };
}

function buildPositionExposureRows(equity, policy) {
  const rows = Object.entries(state.positions)
    .filter(([, position]) => position.quantity > 0)
    .map(([symbol, position]) => {
      const assetItem = getAsset(symbol);
      const value = position.quantity * getPrice(symbol);
      const weightPct = equity ? (value / equity) * 100 : 0;
      const limitPct = assetItem.type === "stock" ? policy.maxSingleStockWeight * 100 : 100;
      return {
        key: symbol,
        label: `${symbol} · ${assetItem.maskedName}`,
        weightPct,
        level: weightPct > limitPct ? "danger" : weightPct > limitPct * 0.8 ? "warning" : "",
        detail: `${typeLabel(assetItem.type)} · 市值 ${formatCurrency(value)}`,
      };
    })
    .sort((a, b) => b.weightPct - a.weightPct);
  if (!rows.length) {
    return [{
      key: "cash",
      label: "暂无持仓",
      weightPct: 0,
      level: "",
      detail: "当前风险主要来自错过行情，而不是市场波动。",
    }];
  }
  return rows;
}

function buildSectorExposureRows(equity) {
  const sectorMap = new Map();
  Object.entries(state.positions)
    .filter(([, position]) => position.quantity > 0)
    .forEach(([symbol, position]) => {
      const assetItem = getAsset(symbol);
      const value = position.quantity * getPrice(symbol);
      const current = sectorMap.get(assetItem.sector) || { value: 0, symbols: [] };
      current.value += value;
      current.symbols.push(symbol);
      sectorMap.set(assetItem.sector, current);
    });
  const rows = [...sectorMap.entries()]
    .map(([sector, item]) => {
      const weightPct = equity ? (item.value / equity) * 100 : 0;
      return {
        key: sector,
        label: sectorLabel(sector),
        weightPct,
        level: weightPct > riskPolicy.maxSectorWeight * 100 ? "danger" : weightPct > riskPolicy.maxSectorWeight * 80 ? "warning" : "",
        detail: `${item.symbols.join("、")} · ${formatCurrency(item.value)}`,
      };
    })
    .sort((a, b) => b.weightPct - a.weightPct);
  if (!rows.length) {
    return [{
      key: "none",
      label: "暂无行业暴露",
      weightPct: 0,
      level: "",
      detail: "现金比例 100%，没有市场风险暴露。",
    }];
  }
  return rows;
}

function buildGapRiskRows(selectedCase = getCase(), day = state.day) {
  const rows = selectedCase.assets.map((assetItem) => {
    const cappedDay = Math.min(day, assetItem.prices.length - 1);
    const current = assetItem.prices[cappedDay];
    const previous = assetItem.prices[Math.max(0, cappedDay - 1)] || current;
    const gapPct = assetOpenGapPct(assetItem, cappedDay);
    const dayChangePct = assetDayChangePct(assetItem, cappedDay);
    const level = gapRiskLevel(assetItem, gapPct);
    const absGap = Math.abs(gapPct);
    return {
      symbol: assetItem.maskedSymbol,
      name: assetItem.maskedName,
      type: assetItem.type,
      day: cappedDay,
      previousClose: previous.close,
      open: current.open,
      gapPct,
      dayChangePct,
      level,
      detail: cappedDay === 0
        ? "第一天没有前一日收盘价，无法计算隔夜跳空。"
        : level === "danger"
          ? `开盘相对前收跳动 ${formatPlainPercent(absGap)}，止损和市价单都可能无法按昨收附近成交。`
          : level === "warn"
            ? `存在明显开盘跳空。先确认这是消息重定价，还是短期流动性造成。`
            : "开盘跳空不明显，但仍应记住日线止损不是保证成交价。",
    };
  }).sort((a, b) => Math.abs(b.gapPct) - Math.abs(a.gapPct));
  return rows;
}

function buildEventRiskRows(selectedCase = getCase(), day = state.day, lookahead = 3) {
  const events = selectedCase.scheduledEvents || [];
  const visible = events
    .filter((eventItem) => eventItem.day >= day - 1 && eventItem.day <= day + lookahead)
    .sort((a, b) => a.day - b.day || severityRank(b.riskLevel) - severityRank(a.riskLevel));
  if (!visible.length) {
    const next = events.filter((eventItem) => eventItem.day > day).sort((a, b) => a.day - b.day)[0];
    return [{
      key: "no-event-risk",
      day: next?.day ?? day,
      title: next ? "后续有事件窗口" : "暂无事件窗口",
      type: next?.type || "none",
      typeLabel: next ? eventRiskTypeLabel(next.type) : "日历",
      riskLevel: next?.riskLevel || "good",
      level: next ? "good" : "good",
      daysUntil: next ? next.day - day : 0,
      statusLabel: next ? `距离下一节点 ${next.day - day} 天` : "正常",
      detail: next
        ? `最近的已知事件是第 ${displayDay(next.day)} 天。当前还不在事件窗口内，但推进时间前仍要留意仓位。`
        : "本案例没有额外的预设事件日。继续按价格、新闻和风险仪表盘训练。",
    }];
  }
  return visible.map((eventItem) => {
    const daysUntil = eventItem.day - day;
    const level = normalizeEventRiskLevel(eventItem.riskLevel, daysUntil);
    return {
      key: `${eventItem.type}-${eventItem.day}-${eventItem.title}`,
      day: eventItem.day,
      title: eventItem.title,
      type: eventItem.type,
      typeLabel: eventRiskTypeLabel(eventItem.type),
      riskLevel: eventItem.riskLevel || "warn",
      level,
      daysUntil,
      statusLabel: daysUntil === 0 ? "今天" : daysUntil > 0 ? "即将到来" : "刚过去",
      detail: eventItem.detail || defaultEventRiskDetail(eventItem),
    };
  });
}

function normalizeEventRiskLevel(riskLevel, daysUntil = 0) {
  if (riskLevel === "danger") return daysUntil === 0 || daysUntil === 1 ? "danger" : "warn";
  if (riskLevel === "warn") return daysUntil === 0 || daysUntil === 1 ? "warn" : "good";
  return "good";
}

function currentEventRiskWindow(selectedCase = getCase(), day = state.day) {
  return buildEventRiskRows(selectedCase, day, 1)
    .filter((row) => row.key !== "no-event-risk")
    .filter((row) => row.daysUntil >= -1 && row.daysUntil <= 1)
    .sort((a, b) => severityRank(b.level) - severityRank(a.level) || Math.abs(a.daysUntil) - Math.abs(b.daysUntil))[0] || null;
}

function defaultEventRiskDetail(eventItem) {
  return `${eventRiskTypeLabel(eventItem.type)}会改变市场预期。事件日前后优先降低仓位、避免市价追单，并提前写好失效条件。`;
}

function buildStressRows(equity = getPortfolioTotals().equity) {
  const positions = Object.entries(state.positions).filter(([, position]) => position.quantity > 0);
  if (!positions.length) {
    return [{
      id: "cash-only",
      label: "空仓压力测试",
      shock: "无市场冲击",
      loss: 0,
      lossPct: 0,
      afterEquity: equity,
      detail: "当前没有持仓，主要风险是错过行情而不是价格下跌。",
      level: "good",
    }];
  }
  const positionValues = positions.map(([symbol, position]) => ({
    symbol,
    assetItem: getAsset(symbol),
    value: position.quantity * getPrice(symbol),
  }));
  const totalPositionValue = positionValues.reduce((sum, item) => sum + item.value, 0);
  const largestPosition = positionValues.reduce((max, item) => item.value > max.value ? item : max, positionValues[0]);
  const sectorValues = positionValues.reduce((map, item) => {
    const current = map.get(item.assetItem.sector) || { sector: item.assetItem.sector, value: 0, symbols: [] };
    current.value += item.value;
    current.symbols.push(item.symbol);
    map.set(item.assetItem.sector, current);
    return map;
  }, new Map());
  const largestSector = [...sectorValues.values()].sort((a, b) => b.value - a.value)[0];
  return [
    buildStressRow({
      id: "market-5",
      label: "市场快速回撤",
      shock: "全部持仓 -5%",
      shockedValue: totalPositionValue,
      shockPct: -5,
      equity,
      detail: "模拟宽基和单股一起下跌的普通压力日。",
    }),
    buildStressRow({
      id: "market-10",
      label: "市场恐慌日",
      shock: "全部持仓 -10%",
      shockedValue: totalPositionValue,
      shockPct: -10,
      equity,
      detail: "模拟急跌或隔夜利空后的账户损失。",
    }),
    buildStressRow({
      id: "largest-position",
      label: "最大持仓爆雷",
      shock: `${largestPosition.symbol} -15%`,
      shockedValue: largestPosition.value,
      shockPct: -15,
      equity,
      detail: `检验单一标的 ${largestPosition.symbol} 对账户的影响。`,
    }),
    buildStressRow({
      id: "largest-sector",
      label: "最大行业冲击",
      shock: `${sectorLabel(largestSector.sector)} -20%`,
      shockedValue: largestSector.value,
      shockPct: -20,
      equity,
      detail: `覆盖 ${largestSector.symbols.join("、")} 的行业同步下跌。`,
    }),
  ];
}

function buildStressRow({ id, label, shock, shockedValue, shockPct, equity, detail }) {
  const loss = shockedValue * Math.abs(shockPct) / 100;
  const lossPct = equity ? (loss / equity) * 100 : 0;
  return {
    id,
    label,
    shock,
    loss,
    lossPct,
    afterEquity: equity - loss,
    detail,
    level: lossPct >= 8 ? "danger" : lossPct >= 4 ? "warn" : "good",
  };
}

function buildOpenPositionLots(upToDay = state.day) {
  const lots = [];
  chronologicalDecisions()
    .filter((decision) => decision.day <= upToDay)
    .forEach((decision) => {
      if (decision.side === "buy") {
        lots.push({
          id: `${decision.symbol}-${decision.day}-${lots.length}`,
          symbol: decision.symbol,
          quantity: decision.quantity,
          remaining: decision.quantity,
          entryDay: decision.day,
          entryPrice: decision.price || getPrice(decision.symbol, decision.day),
          risk: Number(decision.risk),
          intent: decision.intent,
          horizon: decision.horizon,
          reason: decision.reason || "",
          invalidation: decision.invalidation || "",
          settlement: decision.settlement || null,
        });
        return;
      }
      if (decision.side !== "sell") return;
      let remainingSell = decision.quantity;
      lots
        .filter((lot) => lot.symbol === decision.symbol && lot.remaining > 0)
        .forEach((lot) => {
          if (remainingSell <= 0) return;
          const closeQuantity = Math.min(lot.remaining, remainingSell);
          lot.remaining -= closeQuantity;
          remainingSell -= closeQuantity;
        });
    });

  const matchedBySymbol = lots.reduce((record, lot) => {
    if (lot.remaining > 0) record[lot.symbol] = (record[lot.symbol] || 0) + lot.remaining;
    return record;
  }, {});
  Object.entries(state.positions)
    .filter(([, position]) => position.quantity > 0)
    .forEach(([symbol, position]) => {
      const matched = matchedBySymbol[symbol] || 0;
      const missingQuantity = position.quantity - matched;
      if (missingQuantity <= 0.0001) return;
      lots.push({
        id: `${symbol}-unmatched`,
        symbol,
        quantity: missingQuantity,
        remaining: missingQuantity,
        entryDay: 0,
        entryPrice: position.averageCost || getPrice(symbol),
        risk: Number.NaN,
        intent: "",
        horizon: "",
        reason: "这笔持仓没有对应的买入决策记录。",
        invalidation: "缺少原始失效条件。",
        unmatched: true,
      });
    });

  return lots.filter((lot) => lot.remaining > 0);
}

function findCashAccountSaleWarnings(symbol, quantity, day = state.day) {
  let remainingSell = Number(quantity) || 0;
  const warnings = [];
  buildOpenPositionLots(day)
    .filter((lot) => lot.symbol === symbol && lot.remaining > 0)
    .sort((a, b) => a.entryDay - b.entryDay)
    .forEach((lot) => {
      if (remainingSell <= 0) return;
      const closeQuantity = Math.min(lot.remaining, remainingSell);
      remainingSell -= closeQuantity;
      const paidForDay = Number(lot.settlement?.paidForDay);
      if (lot.settlement?.usesUnsettledCash && Number.isFinite(paidForDay) && day < paidForDay) {
        warnings.push({
          symbol,
          quantity: closeQuantity,
          entryDay: lot.entryDay,
          sellDay: day,
          paidForDay,
          entryPrice: lot.entryPrice,
          type: "good-faith-risk",
          detail: `这批 ${symbol} 在第 ${displayDay(lot.entryDay)} 天动用未结算资金买入，资金预计第 ${displayDay(paidForDay)} 天完成结算；第 ${displayDay(day)} 天卖出可能形成现金账户 good faith 类风险。`,
        });
      }
    });
  return warnings;
}

function buildOpenPositionPlanRows() {
  const rows = buildOpenPositionLots(state.day)
    .map(buildPositionPlanRow)
    .sort((a, b) => severityRank(b.level) - severityRank(a.level) || b.maxAdversePct - a.maxAdversePct);
  if (!rows.length) {
    return [{
      key: "no-position-plan",
      level: "good",
      title: "暂无持仓计划",
      statusLabel: "空仓",
      unrealizedPnl: 0,
      pnlPct: 0,
      maxAdversePct: 0,
      riskLimitPct: 0,
      detail: "当前没有未平仓买入 lot。下一次买入后，这里会持续跟踪失效条件。",
      invalidation: "无",
      actionHint: "继续把观望也当作主动决策记录。",
    }];
  }
  return rows;
}

function buildPositionPlanRow(lot) {
  const assetItem = getAsset(lot.symbol);
  const currentDay = Math.min(state.day, assetItem.prices.length - 1);
  const currentPrice = getPrice(lot.symbol, currentDay);
  const entryPrice = lot.entryPrice || currentPrice;
  const maxAdverse = maxAdverseMoveAfter(assetItem, lot.entryDay, entryPrice);
  const riskLimitPct = Number.isFinite(lot.risk) && lot.risk > 0 ? lot.risk : 0;
  const pnlPct = entryPrice ? ((currentPrice - entryPrice) / entryPrice) * 100 : 0;
  const unrealizedPnl = (currentPrice - entryPrice) * lot.remaining;
  const lastPlanDay = latestPlanTouchDay(lot.symbol, lot.entryDay);
  const daysSincePlan = Math.max(0, state.day - lastPlanDay);
  const lastCheckpoint = latestCheckpointLog(lot.symbol, lot.entryDay);
  const stopPrice = riskLimitPct ? entryPrice * (1 - riskLimitPct / 100) : 0;
  const breached = riskLimitPct && (currentPrice <= stopPrice || maxAdverse.movePct >= riskLimitPct);
  const nearBreach = riskLimitPct && maxAdverse.movePct >= riskLimitPct * 0.75;
  const stale = daysSincePlan >= 5;
  let level = "good";
  let statusLabel = "按计划";
  let actionHint = "继续按原计划观察，不要因为短期波动临时改规则。";
  if (lot.unmatched || !riskLimitPct) {
    level = "danger";
    statusLabel = "缺少计划";
    actionHint = "不要继续加仓。先补写这笔仓位的亏损线、失效条件和退出动作。";
  } else if (breached) {
    level = "danger";
    statusLabel = "触发亏损线";
    actionHint = "必须暂停加仓，并在下一次决策里选择减仓、止损或写明继续持有的新证据。";
  } else if (nearBreach) {
    level = "warn";
    statusLabel = "接近亏损线";
    actionHint = "不要补仓摊低成本。先确认失效条件是否已经接近发生。";
  } else if (stale) {
    level = "warn";
    statusLabel = "计划未复查";
    actionHint = "建议记录一次主动观望或减仓理由，更新你是否仍相信原判断。";
  }
  return {
    key: lot.id,
    symbol: lot.symbol,
    level,
    title: `${lot.symbol} · 第 ${displayDay(lot.entryDay)} 天买入 lot · ${lot.remaining} 股`,
    statusLabel,
    entryDay: lot.entryDay,
    entryPrice,
    currentPrice,
    quantity: lot.remaining,
    pnlPct,
    unrealizedPnl,
    maxAdversePct: maxAdverse.movePct,
    riskLimitPct,
    stopPrice,
    lastPlanDay,
    lastCheckpoint,
    checkpointCount: checkpointLogsForSymbol(lot.symbol, lot.entryDay).length,
    detail: `成本 ${formatCurrency(entryPrice)}，当前 ${formatCurrency(currentPrice)}，已持有 ${Math.max(0, state.day - lot.entryDay)} 天；最近一次计划复查距今 ${daysSincePlan} 天。${lastCheckpoint ? `最近复查：${checkpointBiasLabel(lastCheckpoint.bias)}，${checkpointActionLabel(lastCheckpoint.action)}。` : ""}`,
    invalidation: lot.invalidation || "没有写清楚失效条件。",
    actionHint,
  };
}

function latestPlanTouchDay(symbol, entryDay) {
  const decisionTouches = chronologicalDecisions()
    .filter((decision) => decision.day <= state.day && decision.day >= entryDay)
    .filter((decision) => decision.symbol === symbol)
    .map((decision) => decision.day);
  const logTouches = checkpointLogsForSymbol(symbol, entryDay).map((log) => log.day);
  const touches = [...decisionTouches, ...logTouches];
  return touches.length ? Math.max(...touches) : entryDay;
}

function checkpointLogs() {
  return Array.isArray(state.checkpointLogs) ? state.checkpointLogs : [];
}

function checkpointLogsForSymbol(symbol, entryDay = 0, upToDay = state.day) {
  return checkpointLogs()
    .filter((log) => log.symbol === symbol)
    .filter((log) => log.day <= upToDay && log.day >= entryDay)
    .sort((a, b) => a.day - b.day || String(a.savedAt || "").localeCompare(String(b.savedAt || "")));
}

function latestCheckpointLog(symbol, entryDay = 0, upToDay = state.day) {
  const logs = checkpointLogsForSymbol(symbol, entryDay, upToDay);
  return logs.length ? logs[logs.length - 1] : null;
}

function severityRank(level) {
  if (level === "danger") return 3;
  if (level === "warn" || level === "warning") return 2;
  if (level === "good") return 1;
  return 0;
}

function buildRiskAlerts({ cashPct, positionRows, sectorRows, gapRows, eventRiskRows, settlement, planRows, allocationStatus, contractStatus, policy }) {
  const alerts = [];
  if (contractStatus?.stats?.riskCoolingActive) {
    alerts.push({
      level: "danger",
      title: "风险冷却已启动",
      detail: `第 ${displayDay(contractStatus.stats.riskCoolingBreachDay)} 天最大回撤超过训练合约预算。现在禁止新增买入，只允许观望、减仓、止损或复查。`,
    });
  }
  if (cashPct < policy.reserveCashRatio * 100) {
    alerts.push({ level: "danger", title: "现金低于模式要求", detail: `当前现金 ${formatPlainPercent(cashPct)}，低于 ${formatPlainPercent(policy.reserveCashRatio * 100)}。` });
  } else if (cashPct < policy.reserveCashRatio * 100 + 5) {
    alerts.push({ level: "warn", title: "现金缓冲偏薄", detail: "继续加仓前先想清楚如果明天下跌，你还有没有调整空间。" });
  }
  const concentrated = positionRows.find((item) => item.level === "danger" || item.level === "warning");
  if (concentrated && concentrated.key !== "cash") {
    alerts.push({ level: concentrated.level === "danger" ? "danger" : "warn", title: "单一标的仓位偏高", detail: `${concentrated.label} 已占 ${formatPlainPercent(concentrated.weightPct)}。` });
  }
  const sectorRisk = sectorRows.find((item) => item.level === "danger" || item.level === "warning");
  if (sectorRisk && sectorRisk.key !== "none") {
    alerts.push({ level: sectorRisk.level === "danger" ? "danger" : "warn", title: "行业暴露集中", detail: `${sectorRisk.label} 已占 ${formatPlainPercent(sectorRisk.weightPct)}。` });
  }
  const drawdown = getMaxDrawdown();
  if (drawdown >= 10) alerts.push({ level: "danger", title: "账户回撤较大", detail: `最大回撤 ${formatPlainPercent(drawdown)}，应该先减小错误继续扩大的概率。` });
  else if (drawdown >= 5) alerts.push({ level: "warn", title: "账户回撤提醒", detail: `最大回撤 ${formatPlainPercent(drawdown)}，需要复查仓位和失效条件。` });
  const gapDanger = (gapRows || []).find((row) => row.level === "danger");
  const gapWarnCount = (gapRows || []).filter((row) => row.level === "warn").length;
  if (gapDanger) {
    alerts.push({ level: "danger", title: "隔夜跳空风险", detail: `${gapDanger.symbol} 开盘跳空 ${formatPercent(gapDanger.gapPct)}。不要假设止损一定能按昨收附近成交。` });
  } else if (gapWarnCount) {
    alerts.push({ level: "warn", title: "开盘跳空", detail: `当前有 ${gapWarnCount} 个标的出现明显开盘跳空，市价单和追价都要降速。` });
  }
  const eventDanger = (eventRiskRows || []).find((row) => row.level === "danger" && row.key !== "no-event-risk");
  const eventWarnCount = (eventRiskRows || []).filter((row) => row.level === "warn" && row.key !== "no-event-risk").length;
  if (eventDanger) {
    alerts.push({ level: "danger", title: "事件日风险", detail: `第 ${displayDay(eventDanger.day)} 天 ${eventDanger.title}：${eventDanger.detail}` });
  } else if (eventWarnCount) {
    alerts.push({ level: "warn", title: "临近事件窗口", detail: `当前有 ${eventWarnCount} 个事件窗口需要降速。不要把普通交易日的仓位纪律套到事件日。` });
  }
  if (settlement?.unsettledProceeds > 0) {
    alerts.push({ level: "warn", title: "卖出款未结算", detail: `当前有 ${formatCurrency(settlement.unsettledProceeds)} 卖出款等待 ${settlement.cycle} 结算。连续买卖前先看已结算现金。` });
  }
  const planDanger = planRows.find((item) => item.level === "danger" && item.key !== "no-position-plan");
  const planWarn = planRows.find((item) => item.level === "warn" && item.key !== "no-position-plan");
  if (planDanger) {
    alerts.push({ level: "danger", title: "持仓计划失效", detail: `${planDanger.title}：${planDanger.actionHint}` });
  } else if (planWarn) {
    alerts.push({ level: "warn", title: "持仓计划需要复查", detail: `${planWarn.title}：${planWarn.actionHint}` });
  }
  const allocationFail = allocationStatus?.items.find((item) => item.status === "fail");
  const allocationWarn = allocationStatus?.items.find((item) => item.status === "warn");
  if (allocationFail) {
    alerts.push({ level: "danger", title: "配置蓝图失守", detail: allocationFail.detail });
  } else if (allocationWarn) {
    alerts.push({ level: "warn", title: "配置蓝图提醒", detail: allocationWarn.detail });
  }
  const todayTrades = state.decisions.filter((item) => item.day === state.day && item.side !== "hold").length;
  if (todayTrades >= policy.maxTradesPerDay) alerts.push({ level: "danger", title: "今日交易次数已满", detail: "今天不能再新增交易。请用观望记录代替冲动操作。" });
  if (!alerts.length) alerts.push({ level: "good", title: "当前风险结构正常", detail: "没有触发明显风险提醒，但仍要按任务卡执行，不要因为绿色提示就放松纪律。" });
  return alerts;
}

function buildEquitySeries() {
  const points = state.equityCurve.map((item) => ({ day: item.day, value: item.equity }));
  if (!points.some((item) => item.day === state.day)) points.push({ day: state.day, value: getPortfolioTotals().equity });
  return points.sort((a, b) => a.day - b.day);
}

function buildBenchmarkEquitySeries(selectedCase) {
  const benchmark = selectedCase.assets.find((item) => item.type === "etf") || selectedCase.assets[0];
  const shares = riskPolicy.initialCash / benchmark.prices[0].close;
  const maxDay = Math.min(state.day, benchmark.prices.length - 1);
  return benchmark.prices.slice(0, maxDay + 1).map((price, day) => ({ day, value: shares * price.close }));
}

function drawEquityChart(selectedCase, dashboard = buildRiskDashboard(selectedCase)) {
  const canvas = elements.equityChart;
  const ctx = canvas.getContext("2d");
  const dpr = window.devicePixelRatio || 1;
  const rect = canvas.getBoundingClientRect();
  canvas.width = Math.max(1, Math.floor(rect.width * dpr));
  canvas.height = Math.max(1, Math.floor(rect.height * dpr));
  ctx.scale(dpr, dpr);

  const width = rect.width;
  const height = rect.height;
  const padding = { top: 24, right: 52, bottom: 30, left: 58 };
  const allPoints = [...dashboard.equitySeries, ...dashboard.benchmarkSeries];
  const min = Math.min(...allPoints.map((item) => item.value), riskPolicy.initialCash * 0.95);
  const max = Math.max(...allPoints.map((item) => item.value), riskPolicy.initialCash * 1.05);
  const range = Math.max(1, max - min);
  const maxDay = Math.max(1, state.day, currentCaseLength());
  const plotWidth = width - padding.left - padding.right;
  const plotHeight = height - padding.top - padding.bottom;

  ctx.clearRect(0, 0, width, height);
  ctx.strokeStyle = "#d5dee4";
  ctx.lineWidth = 1;
  for (let index = 0; index < 4; index += 1) {
    const y = padding.top + (plotHeight / 3) * index;
    ctx.beginPath();
    ctx.moveTo(padding.left, y);
    ctx.lineTo(width - padding.right, y);
    ctx.stroke();
  }

  drawEquityLine(ctx, dashboard.benchmarkSeries, { min, range, maxDay, padding, plotWidth, plotHeight, color: "#6c7a86", dashed: true });
  drawEquityLine(ctx, dashboard.equitySeries, { min, range, maxDay, padding, plotWidth, plotHeight, color: "#0f766e", dashed: false });

  ctx.fillStyle = "#6c7a86";
  ctx.font = "12px Segoe UI, Arial";
  ctx.textAlign = "left";
  ctx.fillText("你的账户", padding.left, 16);
  ctx.fillStyle = "#0f766e";
  ctx.fillRect(padding.left + 58, 8, 18, 3);
  ctx.fillStyle = "#6c7a86";
  ctx.fillText("买入持有 ETF", padding.left + 92, 16);
  ctx.setLineDash([5, 4]);
  ctx.beginPath();
  ctx.moveTo(padding.left + 168, 10);
  ctx.lineTo(padding.left + 188, 10);
  ctx.stroke();
  ctx.setLineDash([]);
  ctx.textAlign = "right";
  ctx.fillText(formatCurrency(max), width - 10, padding.top + 4);
  ctx.fillText(formatCurrency(min), width - 10, height - padding.bottom);
  ctx.textAlign = "left";
  ctx.fillText("第 1 天", padding.left, height - 10);
  ctx.textAlign = "right";
  ctx.fillText(`第 ${displayDay(state.day)} 天`, width - padding.right, height - 10);
}

function drawEquityLine(ctx, points, options) {
  if (!points.length) return;
  const { min, range, maxDay, padding, plotWidth, plotHeight, color, dashed } = options;
  ctx.strokeStyle = color;
  ctx.lineWidth = dashed ? 1.8 : 2.6;
  ctx.setLineDash(dashed ? [5, 4] : []);
  ctx.beginPath();
  points.forEach((point, index) => {
    const x = padding.left + (point.day / maxDay) * plotWidth;
    const y = padding.top + (1 - (point.value - min) / range) * plotHeight;
    if (index === 0) ctx.moveTo(x, y);
    else ctx.lineTo(x, y);
  });
  ctx.stroke();
  ctx.setLineDash([]);
}

function collectSignals(selectedCase, day) {
  const signals = [];
  buildEventRiskRows(selectedCase, day, 0)
    .filter((item) => item.key !== "no-event-risk" && item.daysUntil === 0)
    .forEach((item) => signals.push({
      title: "事件日风险",
      detail: `今天是${item.typeLabel}：${item.title}。${item.detail}`,
      type: "event-risk",
      day,
    }));
  selectedCase.news
    .filter((item) => item.day === day && item.category === "important")
    .forEach((item) => signals.push({ title: "重要新闻", detail: item.title }));

  selectedCase.assets.forEach((item) => {
    if (day <= 0 || day >= item.prices.length) return;
    const change = ((item.prices[day].close - item.prices[day - 1].close) / item.prices[day - 1].close) * 100;
    const threshold = item.type === "etf" ? 3 : 8;
    if (Math.abs(change) >= threshold) {
      signals.push({
        title: `${item.maskedSymbol} 剧烈波动`,
        detail: `单日涨跌 ${formatPercent(change)}，系统暂停让你重新判断。`,
      });
    }
  });

  signals.push(...collectPositionTriggerSignals(selectedCase, day));

  const totals = getPortfolioTotals();
  if (state.equityCurve.length > 2) {
    const peak = Math.max(...state.equityCurve.map((item) => item.equity));
    const drawdown = peak ? ((peak - totals.equity) / peak) * 100 : 0;
    if (drawdown >= 5) {
      signals.push({ title: "账户回撤提醒", detail: `账户从高点回撤 ${formatPlainPercent(drawdown)}，需要检查仓位。` });
    }
  }
  return signals;
}

function collectPositionTriggerSignals(selectedCase, day) {
  if (day <= 0) return [];
  return buildOpenPositionLots(day)
    .filter((lot) => !lot.unmatched && lot.entryDay < day && Number.isFinite(lot.risk) && lot.risk > 0)
    .flatMap((lot) => {
      const assetItem = selectedCase.assets.find((item) => item.maskedSymbol === lot.symbol) || getAsset(lot.symbol);
      const bar = assetItem.prices[Math.min(day, assetItem.prices.length - 1)];
      if (!bar) return [];
      const stopPrice = lot.entryPrice * (1 - lot.risk / 100);
      const rewardTargetPrice = lot.entryPrice * (1 + lot.risk * 2 / 100);
      const items = [];
      if (Number(bar.low) <= stopPrice) {
        items.push({
          title: `${lot.symbol} 亏损线触发`,
          detail: `${lot.symbol} 第 ${displayDay(day)} 天低点 ${formatCurrency(bar.low)} 已触及你买入时的亏损线 ${formatCurrency(stopPrice)}。请先处理失效条件，不要继续推进时间。`,
          type: "stop-trigger",
          symbol: lot.symbol,
          day,
        });
      }
      if (Number(bar.high) >= rewardTargetPrice) {
        items.push({
          title: `${lot.symbol} 2R 盈利窗口`,
          detail: `${lot.symbol} 第 ${displayDay(day)} 天高点 ${formatCurrency(bar.high)} 达到 2R 目标 ${formatCurrency(rewardTargetPrice)}。请执行止盈、减仓、再平衡或写明继续持有理由。`,
          type: "profit-trigger",
          symbol: lot.symbol,
          day,
        });
      }
      return items;
    });
}

function setCase(caseId) {
  const targetCase = getCase(caseId);
  const pathStatus = getCasePathStatus(targetCase);
  if (!pathStatus.unlocked) {
    showMessage(pathStatus.reason);
    return;
  }
  const carriedBlindSession = state.blindSession?.active && caseId !== state.caseId ? state.blindSession : null;
  if (carriedBlindSession) {
    recordBlindViolation("manual-case-switch", `从 ${displayCaseId(getCase())} 手动切换到 ${displayCaseId(targetCase)}。`, "danger");
  }
  stopPlayback();
  state = defaultState(caseId, state.mode);
  if (carriedBlindSession) {
    state.blindSession = {
      ...carriedBlindSession,
      active: true,
      violations: carriedBlindSession.violations || [],
    };
  }
  saveState();
  showMessage("已切换案例，训练重新开始。");
  render();
}

function startRandomBlindExam(options = {}) {
  if (!options.skipConfirm && state.decisions.length && !window.confirm("随机盲测会清空当前案例进度，并切换到考试模式。确定吗？")) return;
  const pick = chooseRandomBlindCase();
  stopPlayback();
  state = defaultState(pick.caseId, "exam");
  state.blindSession = {
    ...defaultBlindSession(),
    active: true,
    random: true,
    startedAt: new Date().toISOString(),
    startedCaseId: pick.caseId,
    startedMode: "exam",
    pickPoolSize: pick.poolSize,
    avoidedRecent: pick.avoidedRecent,
    violations: [],
  };
  if (options.activePlan) {
    state.activeTrainingPlan = {
      ...options.activePlan,
      caseId: pick.caseId,
      caseTitle: getCase(pick.caseId).maskedTitle,
      modeSuggestion: "exam",
      launchMode: "random-blind",
      startedAt: new Date().toISOString(),
    };
  }
  state.pauseReason = options.pauseReason || `随机盲测已开始：${displayCaseId(getCase(pick.caseId))}。系统已隐藏案例主题、课程提示和关键节点原因。`;
  saveState();
  showMessage(options.message || `已进入随机盲测：${displayCaseId(getCase(pick.caseId))}。`);
  render();
}

function recordBlindViolation(type, detail, level = "warn") {
  if (!state.blindSession?.active || state.revealed) return;
  const violations = Array.isArray(state.blindSession.violations) ? state.blindSession.violations : [];
  violations.push({
    type,
    level,
    detail,
    day: state.day,
    mode: state.mode,
    caseId: state.caseId,
    recordedAt: new Date().toISOString(),
  });
  state.blindSession.violations = violations;
}

function getLatestRemediation() {
  return [...profile.completedRuns].reverse().find((item) => item.remediation)?.remediation || null;
}

function startRemediation(source = "profile") {
  const remediation = source === "review" && state.revealed
    ? buildReview(getCase()).remediation
    : getLatestRemediation();
  if (!remediation || !allCases().some((item) => item.id === remediation.nextCaseId)) {
    showMessage("暂时没有可启动的补练处方。");
    return;
  }
  const previousCaseId = state.caseId;
  stopPlayback();
  state = defaultState(remediation.nextCaseId, state.mode);
  state.activeRemediation = {
    ...remediation,
    fromCaseId: previousCaseId,
    startedAt: new Date().toISOString(),
  };
  state.pauseReason = `已进入补练：${remediation.title}。`;
  saveState();
  showMessage(`已开始补练：${remediation.nextCaseId}。`);
  render();
}

function startScheduledTrainingCase(caseId, focus = "") {
  const targetCase = allCases().find((item) => item.id === caseId);
  if (!targetCase) {
    showMessage("训练任务对应的案例不存在。");
    return;
  }
  const status = getCasePathStatus(targetCase);
  if (!status.unlocked) {
    showMessage(status.reason);
    return;
  }
  if (state.decisions.length && !window.confirm("开始训练计划会清空当前案例进度，确定吗？")) return;
  const activePlan = createActiveTrainingPlanSnapshot(caseId, focus);
  if (activePlan.launchMode === "random-blind") {
    startRandomBlindExam({
      activePlan,
      skipConfirm: true,
      pauseReason: `已按今日训练计划进入随机盲测：${activePlan.focus}。系统已隐藏案例主题、课程提示和关键节点原因。`,
      message: `已按计划进入随机盲测：${activePlan.focus}。`,
    });
    return;
  }
  setCase(caseId);
  state.activeTrainingPlan = activePlan;
  state.mode = activePlan.modeSuggestion === "advanced" ? "advanced" : "novice";
  state.pauseReason = `已按今日训练计划进入 ${caseId}：${activePlan.focus}。`;
  saveState();
  showMessage(`已开始今日训练计划：${activePlan.focus}。`);
  render();
}

function startMistakeNotebookDrill(key) {
  const report = buildMistakeNotebookReport(profile.completedRuns, profile.mistakeCounts);
  const card = report.cards.find((item) => item.key === key);
  if (!card) {
    showMessage("没有找到这张错题卡。");
    return;
  }
  const targetCase = allCases().find((item) => item.id === card.drillCaseId);
  if (!targetCase) {
    showMessage("错题卡对应的案例不存在。");
    return;
  }
  const status = getCasePathStatus(targetCase);
  if (!status.unlocked) {
    showMessage(status.reason);
    return;
  }
  if (state.decisions.length && !window.confirm("开始错题补练会清空当前案例进度，确定吗？")) return;
  const activePlan = createMistakeNotebookTrainingPlan(card);
  setCase(card.drillCaseId);
  state.activeTrainingPlan = activePlan;
  state.mode = "novice";
  state.pauseReason = `已进入错题补练：${card.label}。`;
  saveState();
  showMessage(`已开始错题补练：${card.label}。`);
  render();
}

function startReviewScheduleDrill(caseId, focus = "间隔复训") {
  const targetCase = allCases().find((item) => item.id === caseId);
  if (!targetCase) {
    showMessage("复训日程对应的案例不存在。");
    return;
  }
  const status = getCasePathStatus(targetCase);
  if (!status.unlocked) {
    showMessage(status.reason);
    return;
  }
  if (state.decisions.length && !window.confirm("开始间隔复训会清空当前案例进度，确定吗？")) return;
  setCase(caseId);
  state.activeTrainingPlan = createReviewScheduleTrainingPlan(caseId, focus);
  state.mode = "novice";
  state.pauseReason = `已进入间隔复训：${focus}。`;
  saveState();
  showMessage(`已开始间隔复训：${focus}。`);
  render();
}

function createMistakeNotebookTrainingPlan(card) {
  const caseItem = getCase(card.drillCaseId);
  return {
    title: `错题补练：${card.label}`,
    caseId: card.drillCaseId,
    caseTitle: caseItem.maskedTitle,
    focus: card.label,
    priority: card.level === "danger" ? "high" : "normal",
    reason: `错题本显示“${card.label}”出现 ${card.count} 次，优先级 ${card.priorityScore}/100。`,
    constraint: card.constraint,
    passCriteria: card.passCriteria || mistakeNotebookPassCriteria(card.label, remediationRules[card.label], notebookFallbackRule(card.label)),
    estimatedMinutes: card.level === "danger" ? 45 : 35,
    modeSuggestion: "novice",
    launchMode: "mistake-drill",
    stopRules: [
      "出现红色教练提醒，不提交原动作，先改为观望或重写计划。",
      "如果准备违反错题卡硬限制，必须停止推进并记录原因。",
      "复盘时必须写下一条能防止同类错题复发的规则。",
    ],
    startedAt: new Date().toISOString(),
  };
}

function createReviewScheduleTrainingPlan(caseId, focus = "间隔复训") {
  const caseItem = getCase(caseId);
  return {
    title: `间隔复训：${focus}`,
    caseId,
    caseTitle: caseItem.maskedTitle,
    focus,
    priority: "normal",
    reason: `复训日程要求重新验证“${focus}”，避免旧弱点复发。`,
    constraint: "本轮只验证一个复训重点：先写合约和失效条件，出现红色提醒不新增风险，复盘必须说明旧问题有没有复发。",
    passCriteria: [
      "纪律评分达到 75/100 以上。",
      "任务通过，且没有违反本轮复训重点。",
      "至少保存一条能防止旧问题复发的复盘规则。",
    ],
    estimatedMinutes: 35,
    modeSuggestion: "novice",
    launchMode: "review-schedule",
    stopRules: [
      "没有写清复训重点，不开始交易。",
      "复训重点再次被触发时，不继续加仓，只能观望、减仓或重写计划。",
      "结束后必须先看过程评分，再看收益。",
    ],
    startedAt: new Date().toISOString(),
  };
}

function importCsvCase(event) {
  event.preventDefault();
  try {
    const title = elements.importTitleInput.value.trim();
    const symbol = elements.importSymbolInput.value.trim();
    const csvText = elements.importCsvInput.value;
    assertImportTextSize(csvText, CSV_IMPORT_CHAR_LIMIT, "CSV");
    const hasSymbolColumn = splitCsvLine(csvText.split(/\r?\n/).find((line) => line.trim()) || "")
      .map((item) => item.toLowerCase())
      .includes("symbol");
    if (!symbol && !hasSymbolColumn) throw new Error("单标的 CSV 请输入真实代码；多标的 CSV 可在表头加入 Symbol。");
    const assets = parseCsvAssets(csvText, symbol || "CUSTOM");
    const qualityReport = buildCsvQualityReport(assets);
    renderImportQualityReport(qualityReport);
    const importedCase = createImportedCase({ title, symbol: symbol || assets[0].symbol, rows: assets[0].rows, assets, qualityReport });
    customCaseLibrary.push(importedCase);
    saveCustomCases();
    const rowCount = assets.reduce((sum, item) => sum + item.rows.length, 0);
    const qualitySuffix = qualityReport.status === "good" ? "数据体检通过。" : `数据体检提示：${qualityReport.warnings.length} 个注意点。`;
    elements.importMessage.textContent = `已导入 ${importedCase.id}，${assets.length} 个标的，共 ${rowCount} 条行情。${qualitySuffix}`;
    elements.importTitleInput.value = "";
    elements.importSymbolInput.value = "";
    elements.importCsvInput.value = "";
    renderImportQualityReport(null);
    setCase(importedCase.id);
  } catch (error) {
    elements.importMessage.textContent = error.message;
    renderImportQualityReport(null);
  }
}

function importScenarioPackageCase() {
  try {
    importScenarioPackageFromText(elements.importPackageInput.value);
  } catch (error) {
    elements.importMessage.textContent = error.message;
    renderScenarioPackageQualityReport(null, error.message);
  }
}

function importScenarioPackageFromText(packageText, sourceName = "", options = {}) {
  assertImportTextSize(packageText, PACKAGE_IMPORT_CHAR_LIMIT, "JSON 案例包");
  const parsedPayload = parseScenarioPackageJsonPayload(packageText);
  if (isScenarioPackageBundle(parsedPayload)) {
    return importScenarioPackageBundle(parsedPayload, sourceName, options);
  }
  const qualityReport = buildScenarioPackageQualityReport(packageText, { sourceName });
  if (options.renderQuality !== false) renderScenarioPackageQualityReport(qualityReport);
  const importedCase = qualityReport.importedCase;
  importedCase.importQualityReport = qualityReport.priceReport;
  importedCase.importReadiness = qualityReport.readiness;
  importedCase.importStatus = qualityReport.status;
  const duplicateCase = findDuplicateCustomCase(importedCase);
  if (duplicateCase) throw duplicateScenarioPackageError(duplicateCase);
  customCaseLibrary.push(importedCase);
  saveCustomCases();
  elements.importPackageInput.value = "";
  const sourceCount = importedCase.sourcePack.items.filter((item) => item.url).length;
  const sourceText = sourceName ? ` 来源文件：${sourceName}。` : "";
  if (options.showMessage !== false) elements.importMessage.textContent = `已导入案例包 ${importedCase.id}：${importedCase.revealTitle}。${importedCase.assets.length} 个标的，${importedCase.news.length} 条新闻，${sourceCount} 条来源。${sourceText}`;
  const shouldKeepQuality = options.keepQualityOnDanger && qualityReport.status === "danger";
  if (options.clearQuality !== false && !shouldKeepQuality) renderScenarioPackageQualityReport(null);
  if (options.switchCase !== false) setCase(importedCase.id);
  return importedCase;
}

function parseScenarioPackageJsonPayload(packageText) {
  return MarketReplayImporters.parseJsonPayload(packageText);
}

function isScenarioPackageBundle(parsedPayload) {
  return MarketReplayImporters.isScenarioPackageBundle(parsedPayload);
}

function importScenarioPackageBundle(bundle, sourceName = "", options = {}) {
  const summary = {
    total: bundle.cases.length,
    imported: [],
    skipped: [],
    failed: [],
  };
  if (!summary.total) throw new Error("案例库 bundle 没有 cases。");
  bundle.cases.forEach((casePackage, index) => {
    const caseSourceName = sourceName ? `${sourceName}#${index + 1}` : `bundle-case-${index + 1}`;
    try {
      const importedCase = importScenarioPackageFromText(JSON.stringify(casePackage), caseSourceName, {
        renderQuality: false,
        clearQuality: false,
        showMessage: false,
        switchCase: false,
      });
      summary.imported.push({ fileName: caseSourceName, importedCase });
    } catch (error) {
      if (error.code === "duplicate-scenario-package") {
        summary.skipped.push({ fileName: caseSourceName, message: error.message, duplicateCase: error.duplicateCase });
      } else {
        summary.failed.push({ fileName: caseSourceName, message: error.message });
      }
    }
  });
  if (!summary.imported.length) {
    const firstMessage = summary.skipped[0]?.message || summary.failed[0]?.message || "没有成功导入任何案例包。";
    if (options.showMessage !== false) {
      elements.importMessage.textContent = summary.skipped.length
        ? `案例库没有新增案例：${firstMessage}`
        : `案例库导入失败：${firstMessage}`;
    }
    if (options.clearQuality !== false) renderScenarioPackageQualityReport(null, firstMessage);
    if (summary.failed.length) throw new Error(firstMessage);
    return { ok: false, ...summary };
  }
  const lastImported = summary.imported[summary.imported.length - 1].importedCase;
  elements.importPackageInput.value = "";
  if (options.clearQuality !== false) renderScenarioPackageQualityReport(null);
  if (options.switchCase !== false) setCase(lastImported.id);
  if (options.showMessage !== false) elements.importMessage.textContent = caseLibraryImportSummary(summary, lastImported.id);
  return { ok: true, ...summary, lastCaseId: lastImported.id };
}

function caseLibraryImportSummary(summary, lastCaseId) {
  const skippedText = summary.skipped.length
    ? `跳过重复 ${summary.skipped.length} 个。`
    : "";
  const failedText = summary.failed.length
    ? `失败 ${summary.failed.length} 个：${summary.failed.slice(0, 3).map((item) => `${item.fileName}（${item.message}）`).join("；")}。`
    : "";
  return `已导入案例库 ${summary.imported.length}/${summary.total} 个案例，当前切到 ${lastCaseId}。${skippedText}${failedText}`;
}

function readScenarioPackageFile(file, handlers = {}) {
  if (Number.isFinite(file?.size) && file.size > PACKAGE_FILE_BYTE_LIMIT) {
    handlers.onError?.(new Error(`案例包文件太大：${formatByteSize(file.size)}，上限 ${formatByteSize(PACKAGE_FILE_BYTE_LIMIT)}。请拆成多个较小案例包或案例库 bundle。`), file);
    return;
  }
  const reader = new FileReader();
  reader.onload = () => {
    try {
      const packageText = `${reader.result || ""}`;
      assertImportTextSize(packageText, PACKAGE_IMPORT_CHAR_LIMIT, "JSON 案例包");
      const result = importScenarioPackageFromText(packageText, file.name || "", handlers.importOptions || {});
      if (result && Array.isArray(result.imported)) handlers.onBundleSuccess?.(result, file);
      else handlers.onSuccess?.(result, file);
    } catch (error) {
      handlers.onError?.(error, file);
    }
  };
  reader.onerror = () => {
    handlers.onError?.(new Error("读取案例包文件失败。请确认文件是 UTF-8 JSON。"), file);
  };
  reader.readAsText(file, "utf-8");
}

function importScenarioPackageFile(event) {
  const files = Array.from(event.target.files || []);
  if (!files.length) return;
  const summary = {
    total: files.length,
    imported: [],
    skipped: [],
    failed: [],
    remaining: files.length,
  };
  elements.importMessage.textContent = files.length === 1
    ? `正在读取案例包文件：${files[0].name || "未命名文件"}。`
    : `正在读取 ${files.length} 个案例包文件。`;
  files.forEach((file) => {
    readScenarioPackageFile(file, {
      importOptions: {
        renderQuality: files.length === 1,
        clearQuality: false,
        keepQualityOnDanger: files.length === 1,
        showMessage: false,
        switchCase: false,
      },
      onSuccess(importedCase) {
        summary.imported.push({ fileName: file.name || "未命名文件", importedCase });
        finishScenarioPackageFileImport(summary);
      },
      onBundleSuccess(result) {
        summary.total += Math.max(0, result.total - 1);
        summary.imported.push(...result.imported);
        summary.skipped.push(...result.skipped);
        summary.failed.push(...result.failed);
        finishScenarioPackageFileImport(summary);
      },
      onError(error) {
        if (error.code === "duplicate-scenario-package") {
          summary.skipped.push({ fileName: file.name || "未命名文件", message: error.message, duplicateCase: error.duplicateCase });
        } else {
          summary.failed.push({ fileName: file.name || "未命名文件", message: error.message });
        }
        finishScenarioPackageFileImport(summary);
      },
    });
  });
}

function finishScenarioPackageFileImport(summary) {
  summary.remaining -= 1;
  if (summary.remaining > 0) {
    elements.importMessage.textContent = `正在导入案例包：已完成 ${summary.imported.length + summary.skipped.length + summary.failed.length}/${summary.total}。`;
    return;
  }
  elements.importPackageFileInput.value = "";
  if (!summary.imported.length) {
    const firstMessage = summary.skipped[0]?.message || summary.failed[0]?.message || "没有成功导入任何案例包。";
    elements.importMessage.textContent = summary.skipped.length
      ? `没有新增案例包：${firstMessage}`
      : `案例包导入失败：${firstMessage}`;
    renderScenarioPackageQualityReport(null, firstMessage);
    return;
  }
  const lastImported = summary.imported[summary.imported.length - 1].importedCase;
  if (!(summary.total === 1 && lastImported.importStatus === "danger")) renderScenarioPackageQualityReport(null);
  setCase(lastImported.id);
  const failedText = summary.failed.length
    ? `失败 ${summary.failed.length} 个：${summary.failed.slice(0, 3).map((item) => `${item.fileName}（${item.message}）`).join("；")}。`
    : "";
  const skippedText = summary.skipped.length
    ? `跳过重复 ${summary.skipped.length} 个：${summary.skipped.slice(0, 3).map((item) => `${item.fileName}（已有 ${item.duplicateCase?.id || "案例"}）`).join("；")}。`
    : "";
  const importedText = summary.imported.length <= 3
    ? `成功文件：${summary.imported.map((item) => item.fileName).join("、")}。`
    : `成功文件：${summary.imported.slice(0, 3).map((item) => item.fileName).join("、")} 等 ${summary.imported.length} 个。`;
  elements.importMessage.textContent = `已导入 ${summary.imported.length}/${summary.total} 个案例包，当前切到 ${lastImported.id}。${importedText}${skippedText}${failedText}`;
}

function previewImportQuality() {
  const csvText = elements.importCsvInput.value.trim();
  const symbol = elements.importSymbolInput.value.trim();
  if (!csvText) {
    renderImportQualityReport(null);
    elements.importMessage.textContent = "";
    return;
  }
  try {
    assertImportTextSize(csvText, CSV_IMPORT_CHAR_LIMIT, "CSV");
    const hasSymbolColumn = splitCsvLine(csvText.split(/\r?\n/).find((line) => line.trim()) || "")
      .map((item) => item.toLowerCase())
      .includes("symbol");
    if (!symbol && !hasSymbolColumn) {
      renderImportQualityReport(null);
      elements.importMessage.textContent = "单标的 CSV 请输入真实代码；多标的 CSV 可在表头加入 Symbol。";
      return;
    }
    const assets = parseCsvAssets(csvText, symbol || "CUSTOM");
    renderImportQualityReport(buildCsvQualityReport(assets));
    elements.importMessage.textContent = "";
  } catch (error) {
    renderImportQualityReport(null);
    elements.importMessage.textContent = error.message;
  }
}

function previewScenarioPackageQuality() {
  const packageText = elements.importPackageInput.value.trim();
  if (!packageText) {
    renderScenarioPackageQualityReport(null);
    return;
  }
  try {
    assertImportTextSize(packageText, PACKAGE_IMPORT_CHAR_LIMIT, "JSON 案例包");
    renderScenarioPackageQualityReport(buildScenarioPackageQualityReport(packageText));
  } catch (error) {
    renderScenarioPackageQualityReport(null, error.message);
  }
}

function assertImportTextSize(text, limit, label) {
  const length = String(text || "").length;
  if (length > limit) {
    throw new Error(`${label} 内容太大：约 ${formatCharSize(length)}，上限 ${formatCharSize(limit)}。请拆分文件后再导入。`);
  }
}

function formatCharSize(length) {
  const count = Number(length) || 0;
  if (count >= 1_000_000) return `${(count / 1_000_000).toFixed(1)}M 字符`;
  if (count >= 1_000) return `${Math.round(count / 1_000)}K 字符`;
  return `${count} 字符`;
}

function formatByteSize(size) {
  const bytes = Number(size) || 0;
  if (bytes >= 1024 * 1024) return `${(bytes / 1024 / 1024).toFixed(1)}MB`;
  if (bytes >= 1024) return `${Math.round(bytes / 1024)}KB`;
  return `${bytes}B`;
}

function exportProfileData() {
  const payload = buildBackupPayload();
  const filename = `market-replay-backup-${new Date().toISOString().slice(0, 10)}.json`;
  downloadTextFile(filename, JSON.stringify(payload, null, 2), "application/json;charset=utf-8");
  showMessage(`已导出完整备份：${payload.summary.completedRuns} 条训练记录，${payload.summary.customCases} 个自定义案例。`);
  return { ok: true, filename, backup: payload };
}

function exportCustomCaseLibrary() {
  if (!customCaseLibrary.length) {
    showMessage("当前没有自定义案例可导出。先导入 CSV 或 JSON 案例包。");
    return { ok: false, reason: "empty" };
  }
  const payload = buildCustomCaseLibraryExport(customCaseLibrary);
  const filename = `market-replay-case-library-${new Date().toISOString().slice(0, 10)}.json`;
  downloadTextFile(filename, JSON.stringify(payload, null, 2), "application/json;charset=utf-8");
  showMessage(`已导出案例库：${payload.summary.caseCount} 个自定义案例，不包含训练成绩。`);
  return { ok: true, filename, library: payload };
}

function buildCustomCaseLibraryExport(cases = customCaseLibrary) {
  const casePackages = cases.map((caseItem) => buildCasePackageExport(caseItem));
  return {
    schema: "market-replay-case-library",
    schemaVersion: 1,
    exportedAt: new Date().toISOString(),
    app: {
      name: "美股历史盲测训练器",
      purpose: "只导出自定义案例内容，不包含个人训练记录、长期画像或当前账户状态。",
    },
    summary: {
      caseCount: casePackages.length,
      packageSchemaVersion: 1,
    },
    cases: casePackages,
  };
}

function buildBackupPayload(options = {}) {
  const includeCurrentState = options.includeCurrentState !== false;
  const currentState = includeCurrentState ? cloneJson(state) : null;
  return {
    schema: "market-replay-trainer-backup",
    schemaVersion: BACKUP_SCHEMA_VERSION,
    exportedAt: new Date().toISOString(),
    app: {
      name: "美股历史盲测训练器",
      storageKey: STORAGE_KEY,
      profileKey: PROFILE_KEY,
      customCasesKey: CUSTOM_CASES_KEY,
    },
    profile: cloneJson(profile),
    customCases: cloneJson(customCaseLibrary),
    state: currentState,
    summary: {
      completedRuns: (profile.completedRuns || []).length,
      customCases: customCaseLibrary.length,
      currentCaseId: currentState?.caseId || null,
      currentDay: Number.isFinite(Number(currentState?.day)) ? Number(currentState.day) : null,
      revealed: Boolean(currentState?.revealed),
      exportedMode: currentState?.mode || null,
    },
  };
}

function cloneJson(value) {
  return JSON.parse(JSON.stringify(value ?? null));
}

function restoreBackupPayload(parsed, options = {}) {
  if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
    throw new Error("备份文件根节点必须是对象。");
  }
  const nextProfile = normalizeProfileData(parsed.profile || parsed);
  const nextCustomCases = Array.isArray(parsed.customCases) ? parsed.customCases : [];
  const restoredCases = nextCustomCases.map((item, index) => {
    try {
      return createCase(item);
    } catch (error) {
      throw new Error(`第 ${index + 1} 个自定义案例无法恢复：${error.message}`);
    }
  }).filter((item) => item.assets.length > 0);
  profile = nextProfile;
  customCaseLibrary = restoredCases;
  const restoreCurrentState = options.restoreCurrentState !== false;
  if (restoreCurrentState && parsed.state) {
    state = normalizeStateData(parsed.state, state?.mode || "novice");
  } else {
    state = normalizeStateData(state, state?.mode || "novice");
  }
  saveProfile();
  saveCustomCases();
  saveState();
  return {
    schemaVersion: Number(parsed.schemaVersion) || 1,
    completedRuns: profile.completedRuns.length,
    customCases: customCaseLibrary.length,
    restoredState: Boolean(restoreCurrentState && parsed.state),
    currentCaseId: state.caseId,
  };
}

function exportCurrentCasePackage() {
  const selectedCase = getCase();
  const packagePayload = buildCasePackageExport(selectedCase);
  const filename = `market-replay-case-package-${selectedCase.id}-${new Date().toISOString().slice(0, 10)}.json`;
  downloadTextFile(filename, JSON.stringify(packagePayload, null, 2), "application/json;charset=utf-8");
  showMessage(`已导出案例包：${selectedCase.id}。可以粘贴到 JSON 案例包导入区复用。`);
  return { ok: true, filename, package: packagePayload };
}

function buildCasePackageExport(selectedCase = getCase()) {
  const plan = getTrainingPlan(selectedCase);
  const learning = getLearningModule(selectedCase);
  const sourcePack = selectedCase.sourcePack || buildCaseSourcePack(selectedCase);
  return {
    schemaVersion: 1,
    exportedAt: new Date().toISOString(),
    title: selectedCase.revealTitle || selectedCase.maskedTitle,
    maskedTitle: selectedCase.maskedTitle,
    maskedBrief: selectedCase.maskedBrief,
    revealTitle: selectedCase.revealTitle || selectedCase.maskedTitle,
    realPeriod: selectedCase.realPeriod || caseDateRange(selectedCase),
    tags: selectedCase.tags || [],
    dataQuality: selectedCase.dataQuality || "",
    assets: selectedCase.assets.map(exportCasePackageAsset),
    news: selectedCase.news.map((item) => ({
      day: item.day,
      title: item.title,
      category: item.category,
    })),
    scheduledEvents: (selectedCase.scheduledEvents || []).map((item) => ({
      day: item.day,
      title: item.title,
      type: item.type,
      riskLevel: item.riskLevel,
      detail: item.detail || "",
    })),
    lessons: Array.isArray(selectedCase.lessons) ? selectedCase.lessons : learning.rules,
    learning: {
      title: learning.title,
      concept: learning.concept,
      rules: learning.rules,
      terms: learning.terms.map((item) => ({ name: item.name, description: item.description })),
      quiz: {
        question: learning.quiz.question,
        options: learning.quiz.options,
        answer: learning.quiz.answer,
        explanation: learning.quiz.explanation,
      },
    },
    mission: {
      focus: plan.focus,
      objective: plan.objective,
      checklist: plan.checklist,
      passCriteria: plan.passCriteria || missionPassCriteriaFromPlan(plan),
      rules: {
        minHolds: plan.rules.minHolds,
        maxTrades: plan.rules.maxTrades,
        maxTurnoverPct: plan.rules.maxTurnoverPct,
        maxConcentrationPct: plan.rules.maxConcentrationPct,
        calmOnly: plan.rules.calmOnly !== false,
        minNewsJudgments: Number(plan.rules.minNewsJudgments) || 0,
      },
      trap: plan.trap,
      drill: plan.drill,
    },
    sourcePack: {
      title: sourcePack.title || `${selectedCase.revealTitle || selectedCase.maskedTitle} 复盘资料包`,
      summary: sourcePack.summary || "复盘时核对背景、数据和事件口径。",
      items: (sourcePack.items || []).map((item) => ({
        title: item.title || "",
        publisher: item.publisher || "",
        date: item.date || "",
        kind: item.kind || "",
        url: item.url || "",
        reason: item.reason || item.purpose || "",
      })),
    },
  };
}

function exportCasePackageAsset(assetItem) {
  return {
    symbol: assetItem.realSymbol || assetItem.maskedSymbol,
    maskedSymbol: assetItem.maskedSymbol,
    maskedName: assetItem.maskedName,
    type: assetItem.type || "stock",
    sector: assetItem.sector || "custom",
    rows: assetItem.prices.map((row) => ({
      date: row.date,
      open: row.open,
      high: row.high,
      low: row.low,
      close: row.close,
      volume: row.volume || 0,
    })),
  };
}

function missionPassCriteriaFromPlan(plan) {
  const criteria = [
    `至少 ${plan.rules.minHolds} 次主动观望。`,
    `交易次数不超过 ${plan.rules.maxTrades} 次。`,
    `最大单标的仓位不超过 ${formatPlainPercent(plan.rules.maxConcentrationPct)}。`,
  ];
  if (Number(plan.rules.minNewsJudgments) > 0) criteria.push(`至少 ${plan.rules.minNewsJudgments} 条新闻判断。`);
  return criteria;
}

function caseDateRange(selectedCase) {
  const first = selectedCase.assets[0]?.prices[0]?.date || "";
  const last = selectedCase.assets[0]?.prices[selectedCase.assets[0].prices.length - 1]?.date || "";
  return first && last ? `${first} 至 ${last}` : "";
}

function exportCurrentReviewMarkdown() {
  if (!state.revealed) {
    showMessage("复盘后才能导出报告。");
    return { ok: false, message: "复盘后才能导出报告。" };
  }
  const selectedCase = getCase();
  const markdown = buildReviewMarkdown(selectedCase, buildReview(selectedCase));
  const filename = `market-replay-review-${selectedCase.id}-${new Date().toISOString().slice(0, 10)}.md`;
  downloadTextFile(filename, markdown, "text/markdown;charset=utf-8");
  showMessage("复盘报告已导出。");
  return { ok: true, markdown, filename };
}

function downloadTextFile(filename, text, mimeType = "text/plain;charset=utf-8") {
  const blob = new Blob([text], { type: mimeType });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = filename;
  document.body.appendChild(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(url);
}

