function markdownTable(headers, rows) {
  const cleanHeaders = headers.map(markdownCell);
  const cleanRows = rows.map((row) => row.map(markdownCell));
  return [
    `| ${cleanHeaders.join(" | ")} |`,
    `| ${headers.map(() => "---").join(" | ")} |`,
    ...cleanRows.map((row) => `| ${row.join(" | ")} |`),
  ].join("\n");
}

function markdownCell(value) {
  return String(value ?? "")
    .replace(/\r?\n/g, " ")
    .replace(/\|/g, "\\|")
    .trim();
}

function importBackupFile(event) {
  const file = event.target.files?.[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = () => {
    try {
      const parsed = JSON.parse(String(reader.result));
      const summary = restoreBackupPayload(parsed);
      render();
      const stateText = summary.restoredState ? `当前训练恢复到 ${summary.currentCaseId}。` : "旧版备份没有当前训练状态，已保留当前训练。";
      window.alert(`已导入备份：${summary.completedRuns} 条训练记录，${summary.customCases} 个自定义案例。${stateText}`);
    } catch (error) {
      window.alert(`导入失败：${error.message}`);
    } finally {
      elements.backupFileInput.value = "";
    }
  };
  reader.readAsText(file, "utf-8");
}

function deleteCustomCase(caseId) {
  const target = customCaseLibrary.find((item) => item.id === caseId);
  if (!target) return;
  if (!window.confirm(`删除自定义案例 ${target.maskedTitle}？`)) return;
  customCaseLibrary = customCaseLibrary.filter((item) => item.id !== caseId);
  saveCustomCases();
  if (state.caseId === caseId) state = defaultState(allCases()[0].id, state.mode);
  saveState();
  render();
}

function resetProfileData() {
  if (!window.confirm("这会清空长期画像和课程完成记录，但不会删除当前训练和自定义案例。确定吗？")) return;
  profile = loadProfileFromScratch();
  saveProfile();
  render();
}

function nextDay(step = 1, auto = false) {
  if (state.revealed) return;
  const maxDay = currentCaseLength();
  const targetDay = Math.min(maxDay, state.day + step);
  const dayEvents = [];
  while (state.day < targetDay) {
    state.day += 1;
    dayEvents.push(...processSettlementLedger());
    dayEvents.push(...processCorporateActions());
    dayEvents.push(...processPendingOrders());
    updateEquityCurve();
  }
  const signals = collectSignals(getCase(), state.day);
  if (state.day >= maxDay) {
    state.pauseReason = "案例已到最后一天，系统已自动进入复盘。";
    state.revealReadinessSnapshot = buildRevealReadiness(getCase());
    state.revealed = true;
    stopPlayback();
    recordCompletedRun();
  } else if (auto && signals.length) {
    state.pauseReason = signals[0].detail;
    stopPlayback();
  } else {
    state.pauseReason = dayEvents.length
      ? `${dayEvents.map((event) => event.message).join(" ")}`
      : `已推进到第 ${displayDay(state.day)} 天。`;
  }
  saveState();
  render();
}

function prevDay() {
  if (state.decisions.length || activePendingOrders().length) {
    showMessage("已经做过决策，不能回到过去修改历史。");
    return;
  }
  state.day = Math.max(0, state.day - 1);
  state.pauseReason = `回到第 ${displayDay(state.day)} 天。`;
  saveState();
  render();
}

function activePendingOrders() {
  return MarketReplayRuntime.activePendingOrders(state);
}

function processSettlementLedger() {
  return MarketReplayRuntime.processSettlementLedger({
    state,
    settlementPolicy,
    formatCurrency,
  });
}

function recordSettlementEntry({ symbol, quantity, price, amount, tradeDay = state.day }) {
  return MarketReplayRuntime.recordSettlementEntry({
    state,
    settlementPolicy,
    symbol,
    quantity,
    price,
    amount,
    tradeDay,
    currentCaseLength: currentCaseLength(),
    roundPrice,
  });
}

function processCorporateActions() {
  return MarketReplayRuntime.processCorporateActions({
    state,
    selectedCase: getCase(),
    taxProfile: normalizedTaxProfile(),
    roundPrice,
    formatCurrency,
    formatPlainPercent,
    formatNumber,
  });
}

function corporateActionKey(selectedCase, action) {
  return MarketReplayRuntime.corporateActionKey(selectedCase, action);
}

function corporateActionTypeLabel(type) {
  return MarketReplayRuntime.corporateActionTypeLabel(type);
}

function corporateActionHint(action) {
  return MarketReplayRuntime.corporateActionHint(action, {
    taxProfile: normalizedTaxProfile(),
    formatCurrency,
    formatPlainPercent,
  });
}

function corporateActionEffectText(item) {
  return MarketReplayRuntime.corporateActionEffectText(item, {
    formatCurrency,
    formatNumber,
  });
}

function processPendingOrders() {
  return MarketReplayRuntime.processPendingOrders({
    state,
    resolvePendingOrderStatus,
    buildDecisionFromPendingOrder,
    validateBuy,
    executeBuy,
    executeSell,
    findCashAccountSaleWarnings,
    decisionLabel,
    formatCurrency,
  });
}

function resolvePendingOrderStatus(order, day) {
  const assetItem = getAsset(order.symbol);
  const bar = assetItem.prices[Math.min(day, assetItem.prices.length - 1)];
  return MarketReplayOrders.resolvePendingOrderStatus(order, { day, bar });
}

function getLimitOrderFill(order, day) {
  const assetItem = getAsset(order.symbol);
  const bar = assetItem.prices[Math.min(day, assetItem.prices.length - 1)];
  return MarketReplayOrders.getLimitOrderFill(order, { day, bar });
}

function buildDecisionFromPendingOrder(order, fill) {
  const amount = roundPrice(fill.price * order.quantity);
  const liquidity = buildLiquidityScenario({
    side: order.side,
    symbol: order.symbol,
    quantity: order.quantity,
    price: fill.price,
    amount,
    day: fill.day,
  });
  return {
    ...order.decision,
    day: fill.day,
    price: fill.price,
    amount,
    referencePrice: fill.price,
    frictionCost: 0,
    frictionBps: 0,
    funding: buildDecisionFundingSnapshot(amount),
    settlement: buildDecisionSettlementSnapshot(buildSettlementScenario({ side: order.side, amount, nextCash: order.side === "sell" ? state.cash + amount : state.cash - amount })),
    liquidity: {
      level: liquidity.level,
      volumeSharePct: liquidity.volumeSharePct,
      dollarVolumeSharePct: liquidity.dollarVolumeSharePct,
      impactBps: liquidity.impactBps,
      impactCost: liquidity.impactCost,
      dayVolume: liquidity.dayVolume,
    },
    orderStatus: "filled",
    orderSubmittedDay: order.createdDay,
    orderFilledDay: fill.day,
    orderId: order.id,
  };
}

function jumpToNextEvent() {
  if (state.revealed) return;
  const next = getCase().keyDays.find((day) => day > state.day);
  if (!next) {
    nextDay(currentCaseLength() - state.day, false);
    return;
  }
  nextDay(next - state.day, false);
  state.pauseReason = `已跳到下一个关键节点：第 ${displayDay(state.day)} 天。`;
  saveState();
  render();
}

function togglePlayback() {
  if (playTimer) {
    stopPlayback();
    state.pauseReason = "已暂停。";
    saveState();
    render();
    return;
  }
  if (state.revealed) return;
  const speed = elements.speedInput.value;
  if (speed === "manual") {
    nextDay(1, false);
    return;
  }
  const step = speed === "month" ? 21 : speed === "week" ? 5 : 1;
  playTimer = window.setInterval(() => nextDay(step, true), 1000);
  state.pauseReason = `播放中：${speedLabel(speed)}。遇到关键节点会自动暂停。`;
  render();
}

function stopPlayback() {
  if (!playTimer) return;
  window.clearInterval(playTimer);
  playTimer = null;
}

function cancelPendingOrder(orderId, reason = "用户主动取消") {
  const order = (state.pendingOrders || []).find((item) => item.id === orderId);
  if (!order) return { ok: false, message: "没有找到这张挂单。" };
  if (order.status !== "active") return { ok: false, message: "这张挂单已经不是等待状态。" };
  order.status = "canceled";
  order.closedDay = state.day;
  order.closedAt = new Date().toISOString();
  order.cancelReason = reason;
  saveState();
  showMessage(`已取消限价单：${order.symbol} ${decisionLabel(order.side)} ${order.quantity} 股。`);
  render();
  return { ok: true, order };
}

function placeDecision(event) {
  event.preventDefault();
  if (state.revealed) {
    showMessage("案例已经复盘，不能再追加交易。请开始新训练。");
    return;
  }
  const side = state.selectedSide;
  const symbol = elements.symbolInput.value;
  const quantity = side === "hold" ? 0 : Number.parseInt(elements.quantityInput.value, 10);
  const intent = elements.intentInput.value;
  const horizon = elements.horizonInput.value;
  const planChecks = {
    risk: elements.checkedRiskInput.checked,
    mission: elements.checkedMissionInput.checked,
    invalidation: elements.checkedInvalidationInput.checked,
  };
  const evidenceSources = getEvidenceSourcesFromInputs();
  const emotion = elements.emotionInput.value;
  const risk = Number.parseFloat(elements.riskInput.value);
  const confidence = Number.parseInt(elements.confidenceInput.value, 10);
  const info = elements.infoInput.value.trim();
  const reason = elements.reasonInput.value.trim();
  const invalidation = elements.invalidInput.value.trim();
  const profitPlan = elements.profitPlanInput.value.trim();

  const validation = validateDecision({ side, symbol, quantity, intent, horizon, planChecks, evidenceSources, emotion, risk, confidence, info, reason, invalidation, profitPlan });
  if (!validation.ok) {
    showMessage(validation.message);
    return;
  }

  const preview = buildOrderPreview();
  const orderCheck = validateOrderTicket(side, preview.order);
  if (!orderCheck.ok) {
    showMessage(orderCheck.message);
    return;
  }
  const previewRiskCheck = validatePreviewRisk(side, preview);
  if (!previewRiskCheck.ok) {
    showMessage(previewRiskCheck.message);
    return;
  }
  const liquidityCheck = validateLiquidity(side, preview);
  if (!liquidityCheck.ok) {
    showMessage(liquidityCheck.message);
    return;
  }
  const decisionCoach = createCoachSnapshot(buildDecisionCoach(preview));
  const referencePrice = getPrice(symbol);
  const price = preview.price;
  const amount = preview.amount;
  const baseDecision = {
    day: state.day,
    side,
    symbol,
    quantity,
    price,
    amount,
    referencePrice,
    frictionCost: preview.frictionCost || 0,
    frictionBps: preview.frictionBps || 0,
    funding: buildDecisionFundingSnapshot(amount),
    settlement: buildDecisionSettlementSnapshot(preview.settlementScenario),
    liquidity: preview.liquidityScenario ? {
      level: preview.liquidityScenario.level,
      volumeSharePct: preview.liquidityScenario.volumeSharePct,
      dollarVolumeSharePct: preview.liquidityScenario.dollarVolumeSharePct,
      impactBps: preview.liquidityScenario.impactBps,
      impactCost: preview.liquidityScenario.impactCost,
      dayVolume: preview.liquidityScenario.dayVolume,
    } : null,
    orderType: preview.order?.type || "market",
    limitPrice: preview.order?.limitPrice || 0,
    orderSubmittedDay: state.day,
    orderStatus: "filled",
    intent,
    horizon,
    planChecks,
    evidenceSources,
    coach: decisionCoach,
    emotion,
    risk,
    confidence,
    info,
    reason,
    invalidation,
    profitPlan,
  };
  if (preview.order?.type === "limit" && preview.order.pending) {
    const pending = createPendingOrder(baseDecision, preview.order);
    state.pendingOrders = state.pendingOrders || [];
    state.pendingOrders.unshift(pending);
    saveState();
    clearDecisionInputs();
    showMessage(`限价单已挂起：${symbol} ${decisionLabel(side)} ${quantity} 股，限价 ${formatCurrency(preview.order.limitPrice)}，有效 ${preview.order.expiryDays} 天。`);
    render();
    return;
  }

  if (side === "buy") {
    const riskCheck = validateBuy(symbol, quantity, amount);
    if (!riskCheck.ok) {
      showMessage(riskCheck.message);
      return;
    }
    executeBuy(symbol, quantity, price, amount);
  } else if (side === "sell") {
    const position = state.positions[symbol];
    if (!position || position.quantity < quantity) {
      showMessage("持仓不足，不能卖出。");
      return;
    }
    baseDecision.cashAccountWarnings = findCashAccountSaleWarnings(symbol, quantity, state.day);
    executeSell(symbol, quantity, price, amount);
  }

  state.decisions.unshift(baseDecision);
  updateEquityCurve();
  saveState();
  clearDecisionInputs();
  showMessage(side === "hold" ? "已记录观望理由。" : "决策已记录并成交。");
  render();
}

function validateOrderTicket(side, order) {
  if (side === "hold" || !order || order.type !== "limit") return { ok: true };
  if (!Number.isFinite(order.limitPrice) || order.limitPrice <= 0) {
    return { ok: false, message: "限价单必须填写有效限价。" };
  }
  return { ok: true };
}

function createPendingOrder(decision, order) {
  return {
    id: `order-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
    status: "active",
    createdDay: state.day,
    expiresDay: Math.min(currentCaseLength(), state.day + order.expiryDays),
    side: decision.side,
    symbol: decision.symbol,
    quantity: decision.quantity,
    limitPrice: order.limitPrice,
    expiryDays: order.expiryDays,
    decision: {
      ...decision,
      orderStatus: "pending",
      price: order.limitPrice,
      amount: roundPrice(order.limitPrice * decision.quantity),
      frictionCost: 0,
      frictionBps: 0,
      funding: buildDecisionFundingSnapshot(roundPrice(order.limitPrice * decision.quantity)),
    },
    createdAt: new Date().toISOString(),
  };
}

function validateDecision(input) {
  const policy = currentModePolicy();
  const todayCount = state.decisions.filter((item) => item.day === state.day && item.side !== "hold").length;
  if (todayCount >= policy.maxTradesPerDay && input.side !== "hold") {
    return { ok: false, message: `今天已经交易 ${policy.maxTradesPerDay} 次，不能继续交易。` };
  }
  const lessonGate = buildLessonGate(getCase());
  if (!lessonGate.passed) return { ok: false, message: lessonGate.message };
  if (!input.intent) return { ok: false, message: "请选择操作目的。先定义这笔决策是什么，再决定是否下单。" };
  if (!input.horizon) return { ok: false, message: "请选择计划周期。不同周期不能混用同一套退出理由。" };
  if (input.side === "hold" && input.intent !== "wait") {
    return { ok: false, message: "观望时操作目的应选择“主动观望”。" };
  }
  if (input.side !== "hold" && input.intent === "wait") {
    return { ok: false, message: "买入或卖出时不能选择“主动观望”。请重新选择操作目的。" };
  }
  const checkCount = Object.values(input.planChecks || {}).filter(Boolean).length;
  if (checkCount < 2) return { ok: false, message: "下单前至少完成 2 项计划检查。" };
  if (!input.planChecks?.invalidation) return { ok: false, message: "请先勾选“写好失效条件”，再提交决策。" };
  if (!normalizeEvidenceSources(input.evidenceSources).length) return { ok: false, message: "请至少勾选一个证据来源。不要让决策变成凭感觉。" };
  if (!input.emotion) return { ok: false, message: "请选择当前情绪。情绪记录是训练的一部分。" };
  if (!Number.isFinite(input.risk)) return { ok: false, message: "请选择最多接受亏损。" };
  if (!Number.isInteger(input.confidence) || input.confidence < 1 || input.confidence > 5) return { ok: false, message: "请选择判断信心。信心校准能帮你发现过度自信和过度保守。" };
  if (input.info.length < 8) return { ok: false, message: "请写清楚你现在看到的信息，至少 8 个字。" };
  if (input.reason.length < 12) return { ok: false, message: "请写清楚判断和理由，至少 12 个字。" };
  if (input.invalidation.length < 8) return { ok: false, message: "请写清楚什么情况证明你错了。" };
  if (input.side === "buy" && (!input.profitPlan || input.profitPlan.length < 8)) return { ok: false, message: "买入前请写清楚如果判断对了怎么处理，避免盈利后完全临场反应。" };
  if (input.side !== "hold" && (!Number.isFinite(input.quantity) || input.quantity <= 0)) {
    return { ok: false, message: "买入/卖出数量需要大于 0。" };
  }
  const cooldownCheck = validateRiskCooldown(input);
  if (!cooldownCheck.ok) return cooldownCheck;
  const activePlanCheck = validateActiveTrainingPlan(input);
  if (!activePlanCheck.ok) return activePlanCheck;
  const remediationCheck = validateActiveRemediation(input);
  if (!remediationCheck.ok) return remediationCheck;
  return { ok: true };
}

function validateRiskCooldown(input) {
  const cooldown = getRiskCooldownStatus();
  if (!cooldown.active || input.side !== "buy") return { ok: true };
  return {
    ok: false,
    message: `风险冷却中：第 ${displayDay(cooldown.breachDay)} 天最大回撤 ${formatPlainPercent(cooldown.drawdownPct)} 已超过合约预算 ${formatPlainPercent(cooldown.contract.riskBudgetPct)}，现在不能新增买入。`,
  };
}

function validatePreviewRisk(side, preview) {
  const scenario = preview?.riskScenario;
  if (side === "hold" || !scenario || scenario.level !== "danger") return { ok: true };
  return {
    ok: false,
    message: `单笔风险预算过高：${scenario.detail}`,
  };
}

function validateLiquidity(side, preview) {
  const scenario = preview?.liquidityScenario;
  if (side === "hold" || !scenario || scenario.level !== "danger") return { ok: true };
  return {
    ok: false,
    message: `流动性不足：${scenario.detail}`,
  };
}

function validateActiveTrainingPlan(input) {
  if (!state.activeTrainingPlan) return { ok: true };
  const symbol = input.symbol || state.selectedSymbol;
  const price = getPrice(symbol);
  const previous = getPreviousPrice(symbol);
  const dayChangePct = previous ? ((price - previous) / previous) * 100 : 0;
  const amount = input.side === "hold" ? 0 : Math.max(0, Number(input.quantity) || 0) * price;
  const equity = getPortfolioTotals().equity || riskPolicy.initialCash;
  const amountPct = equity ? (amount / equity) * 100 : 0;
  const check = activeTrainingPlanDecisionCheck({
    side: input.side,
    intent: input.intent,
    horizon: input.horizon,
    amountPct,
    dayChangePct,
    emotion: input.emotion,
  });
  return check.ok
    ? { ok: true }
    : { ok: false, message: `训练计划限制：${check.detail}` };
}

function validateActiveRemediation(input) {
  const remediation = state.activeRemediation;
  if (!remediation) return { ok: true };
  if (remediation.primaryIssue === "缺少观望" && state.day === 0 && input.side !== "hold") {
    return { ok: false, message: "当前补练要求第一天先主动观望，不能直接买入或卖出。" };
  }
  if (remediation.primaryIssue === "短线噪音" && input.horizon === "intraday") {
    return { ok: false, message: "当前补练禁止使用当天周期，请选择数日、数周或整个案例。" };
  }
  if (remediation.primaryIssue === "追高" && input.side === "buy" && input.intent !== "probe") {
    return { ok: false, message: "当前补练要求买入只能作为试探仓，请把操作目的改为试探仓。" };
  }
  return { ok: true };
}

function validateBuy(symbol, quantity, amount) {
  const policy = currentModePolicy();
  const totals = getPortfolioTotals();
  const nextCash = state.cash - amount;
  if (nextCash < 0) return { ok: false, message: "现金不足。" };
  if (nextCash / totals.equity < policy.reserveCashRatio) {
    return { ok: false, message: `${policy.label}模式要求保留至少 ${formatPlainPercent(policy.reserveCashRatio * 100)} 现金。` };
  }
  const assetItem = getAsset(symbol);
  const nextPositions = JSON.parse(JSON.stringify(state.positions));
  const current = nextPositions[symbol] || { quantity: 0, averageCost: 0 };
  const nextQuantity = current.quantity + quantity;
  current.averageCost = (current.quantity * current.averageCost + amount) / nextQuantity;
  current.quantity = nextQuantity;
  nextPositions[symbol] = current;
  const nextPositionValue = getPositionValue(nextPositions);
  const nextEquity = nextCash + nextPositionValue;
  const symbolValue = nextPositions[symbol].quantity * getPrice(symbol);
  if (assetItem.type === "stock" && symbolValue / nextEquity > policy.maxSingleStockWeight) {
    return { ok: false, message: `单只股票超过 ${formatPlainPercent(policy.maxSingleStockWeight * 100)} 上限。减少数量或选择 ETF。` };
  }
  const sectorValue = Object.entries(nextPositions).reduce((sum, [positionSymbol, position]) => {
    return getAsset(positionSymbol).sector === assetItem.sector ? sum + position.quantity * getPrice(positionSymbol) : sum;
  }, 0);
  if (sectorValue / nextEquity > riskPolicy.maxSectorWeight && assetItem.type !== "etf") {
    return { ok: false, message: "单个行业超过 35% 上限。不要把风险集中在一个主题。" };
  }
  return { ok: true };
}

function executeBuy(symbol, quantity, price, amount) {
  const nextPortfolio = MarketReplayPortfolio.applyBuy({ cash: state.cash, positions: state.positions, symbol, quantity, amount });
  state.positions = nextPortfolio.positions;
  state.cash = nextPortfolio.cash;
}

function executeSell(symbol, quantity, price, amount) {
  const nextPortfolio = MarketReplayPortfolio.applySell({ cash: state.cash, positions: state.positions, symbol, quantity, amount });
  state.positions = nextPortfolio.positions;
  state.cash = nextPortfolio.cash;
  recordSettlementEntry({ symbol, quantity, price, amount, tradeDay: state.day });
}

function revealCase() {
  if (state.revealed) return { ok: false, message: "已经揭晓。" };
  const readiness = buildRevealReadiness(getCase());
  if (readiness.blocking && !window.confirm(`${readiness.summary}\n\n仍要提前结束并揭晓答案吗？`)) {
    showMessage("已取消揭晓。继续完成盲测训练。");
    return { ok: false, readiness };
  }
  if (state.blindSession?.active && readiness.blocking) {
    recordBlindViolation("early-reveal", `结束前纪律检查 ${readiness.score}/100，仍选择提前揭晓。`, readiness.score < 50 ? "danger" : "warn");
  }
  state.revealReadinessSnapshot = readiness;
  state.revealed = true;
  state.pauseReason = "已结束训练并揭晓答案。";
  stopPlayback();
  updateEquityCurve();
  recordCompletedRun();
  saveState();
  render();
  return { ok: true, readiness };
}

