  elements.targetWeightInput.addEventListener("input", renderSizingHint);
  elements.targetAmountInput.addEventListener("input", renderSizingHint);
  elements.targetRiskInput.addEventListener("input", renderSizingHint);
  elements.intentInput.addEventListener("change", renderOrderPreview);
  elements.horizonInput.addEventListener("change", renderOrderPreview);
